->\r\n        <div class=\"service\">\r\n            <a href=\"http://127.0.0.1/FH-WEB\">\r\n                <i class=\"fa fa-css3 colored square\"></i>\r\n            </a>\r\n            <h3 class=\"centered\">\r\n                <a href=\"http://127.0.0.1/FH-WEB\" class=\"dark-link\">服务团队</a>\r\n            </h3>\r\n            <p class=\"centered\">资深专家为您提供满意的私人服务.</p>\r\n        </div>\r\n        <!-- End Icon Box -->\r\n    </div>\r\n    <div class=\"four columns\">\r\n        <!-- Icon Box -->\r\n        <div class=\"service\">\r\n            <a href=\"http://127.0.0.1/FH-WEB/\">\r\n                <i class=\"fa fa-magic colored square\"></i>\r\n            </a>\r\n            <h3 class=\"centered\">\r\n                <a href=\"http://127.0.0.1/FH-WEB/\" class=\"dark-link\">核心服务</a>\r\n            </h3>\r\n            <p class=\"centered\">为您提供全面的软件定制服务.</p>\r\n        </div>\r\n        <!-- End Icon Box -->\r\n    </div>\r\n\r\n    <div class=\"clearfix\"></div>\r\n\r\n    <div class=\"separator\"></div>\r\n\r\n    <div class=\"sixteen columns\">\r\n        <h4 class=\"headline\">项目案例&nbsp;&gt</h4>\r\n    </div>\r\n\r\n    <div class=\"four columns identity\">\r\n        <div class=\"work\">\r\n            <a href=\"http://47.96.14.35:8081/uploadFiles/uploadImgs/20180426/9580e719b1ad411e8513365f6d91ffc1.png\" data-gal=\"prettyPhoto\" class=\"work-image\">\r\n                <img src=\"http://47.96.14.35:8081/uploadFiles/uploadImgs/20180426/9580e719b1ad411e8513365f6d91ffc1.png\" alt=\"泄露检测与修复（LDAR）综合管理系统\">\r\n                <div class=\"link-overlay fa fa-search\"></div>\r\n            </a>\r\n            <a href=\"http://47.96.14.35:8081/webnewsdetail.html?NEWID=a936548cb746450e8d2628f765bfcc5d\" class=\"work-name\">泄露检测与修复（LDAR）综合管理系统</a>\r\n            <div class=\"tags\"></div>\r\n        </div>\r\n    </div>\r\n    <div class=\"four columns identity\">\r\n        <div class=\"work\">\r\n            <a href=\"http://47.96.14.35:8081/uploadFiles/uploadImgs/20180426/8d5035de9c014ef7ab310850a5c98c6f.png\" data-gal=\"prettyPhoto\" class=\"work-image\">\r\n                <img src=\"http://47.96.14.35:8081/uploadFiles/uploadImgs/20180426/8d5035de9c014ef7ab310850a5c98c6f.png\" alt=\"济源金光电器设备管理系统\">\r\n                <div class=\"link-overlay fa fa-search\"></div>\r\n            </a>\r\n            <a href=\"http://47.96.14.35:8081/webnewsdetail.html?NEWID=c224736a80014066981881073b42dfc3\" class=\"work-name\">济源金光电器设备管理系统</a>\r\n            <div class=\"tags\"></div>\r\n        </div>\r\n    </div>\r\n    <div class=\"four columns identity\">\r\n        <div class=\"work\">\r\n            <a href=\"http://47.96.14.35:8081/uploadFiles/uploadImgs/20180426/8d5035de9c014ef7ab310850a5c98c6f.png\" data-gal=\"prettyPhoto\" class=\"work-image\">\r\n                <img src=\"http://47.96.14.35:8081/uploadFiles/uploadImgs/20180426/8d5035de9c014ef7ab310850a5c98c6f.png\" alt=\"河南天宏装备设备管理系统\">\r\n                <div class=\"link-overlay fa fa-search\"></div>\r\n            </a>\r\n            <a href=\"http://47.96.14.35:8081/webnewsdetail.html?NEWID=541e1c8700b24eb59a294b2433467a99\" class=\"work-name\">河南天宏装备设备管理系统</a>\r\n            <div class=\"tags\"></div>\r\n        </div>\r\n    </div>\r\n    <div class=\"four columns identity\">\r\n        <div class=\"work\">\r\n            <a href=\"http://47.96.14.35:8081/uploadFiles/uploadImgs/20180426/175841dde67c402cba2b3db8c38d238a.png\" data-gal=\"prettyPhoto\" class=\"work-image\">\r\n                <img src=\"http://47.96.14.35:8081/uploadFiles/uploadImgs/20180426/175841dde67c402cba2b3db8c38d238a.png\" alt=\"山推设备资产管理系统\">\r\n                <div class=\"link-overlay fa fa-search\"></div>\r\n            </a>\r\n            <a href=\"http://47.96.14.35:8081/webnewsdetail.html?NEWID=065c2dc5776941e69496655066b38a6a\" class=\"work-name\">山推设备资产管理系统</a>\r\n            <div class=\"tags\"></div>\r\n        </div>\r\n    </div>\r\n\r\n    <div class=\"clearfix\"></div>\r\n\r\n    <!-- begin promobox -->\r\n    <div class=\"sixteen columns\">\r\n        <div class=\"promo-box clearfix\">\r\n            <div class=\"text\">\r\n                <h3>我们相信  在质量设计</h3>\r\n                <p>任何创意项目都是独一无二的<br /> 具有适当的质量</p>\r\n            </div>\r\n            <a class=\"btn big colored\" href=\"http://www.daaninfo.com/\" target=\"_blank\">\r\n                <i class=\"fa fa-hand-o-right\"></i>了解更多</a>\r\n        </div>\r\n    </div>\r\n    <!-- end promobox -->\r\n\r\n    <div class=\"separator\"></div>\r\n\r\n    <!-- Our Clients  -->\r\n    <div class=\"sixteen columns clients\">\r\n        <h4 class=\"headline\">合作伙伴&nbsp;&gt</h4>\r\n\r\n        <!-- Start brand carousel -->\r\n        <ul id=\"flexiselDemo2\">\r\n            <li onclick=\"window.location.href=\'\'\"><img src=\"http://47.96.14.35:8081/uploadFiles/uploadImgs/20180426/5a07e3de1a594904afd95cdd7d945a1b.jpg\" alt=\"合作伙伴\" /></li>\r\n            <li onclick=\"window.location.href=\'\'\"><img src=\"http://47.96.14.35:8081/uploadFiles/uploadImgs/20180426/1bf0cdb92aec4b5594565b309fe2ae69.png\" alt=\"合作伙伴\" /></li>\r\n            <li onclick=\"window.location.href=\'\'\"><img src=\"http://47.96.14.35:8081/uploadFiles/uploadImgs/20180426/b26633743271423bbbaa4b3bfc1fdf50.png\" alt=\"合作伙伴\" /></li>\r\n            <li onclick=\"window.location.href=\'\'\"><img src=\"http://47.96.14.35:8081/uploadFiles/uploadImgs/20180426/0a488ea68de14d5a83fbc2d58d786380.png\" alt=\"合作伙伴\" /></li>\r\n        </ul>\r\n        <div class=\"clearout\"></div>\r\n        <!-- End brand carousel -->\r\n    </div>\r\n\r\n</div>\r\n<!-- container -->\r\n\r\n<!-- footer 包含底部 -->\r\n<footer class=\"footer\">\r\n    <div class=\"container\">\r\n        <div class=\"footer-top clearfix\">\r\n            <div class=\"four columns\">\r\n                <h3>关于我们</h3>\r\n                <p>文化：诚信、务实、创新、共赢</p>\r\n                <p>愿景：致力于打造中国最好</p>\r\n            </div>\r\n            <div class=\"four columns\">\r\n                <h3>最新消息</h3>\r\n                <div class=\"twitter\">\r\n                    <ul>\r\n                        <!-- Twitter Message 1 -->\r\n                        <li>\r\n								<span>\r\n									《中国制造2025》\r\n								</span>\r\n                        </li>\r\n                        <!-- Twitter Message 2 -->\r\n                        <li>\r\n								<span>\r\n									《中国制造2025》\r\n								</span>\r\n                        </li>\r\n                    </ul>\r\n                </div>\r\n            </div>\r\n            <div class=\"four columns\">\r\n                <h3>技术团队</h3>\r\n                <!--<div class=\"latest-project\">\r\n                    \r\n                    <div class=\"latest-project-item\">\r\n                        <a><img src=\"http://192.168.0.8:8080/FH-WEB3/uploadFiles/uploadImgs/20171116/f89044e67c2240fe98e84f4b93e7aa1b.jpg\" alt=\"技术团队\"></a>\r\n                    </div>\r\n                    <div class=\"latest-project-item\">\r\n                        <a><img src=\"http://192.168.0.8:8080/FH-WEB3/uploadFiles/uploadImgs/20171116/5f95f8f881124b5aa3b41bf381dbba10.jpg\" alt=\"技术团队\"></a>\r\n                    </div>\r\n                    <div class=\"latest-project-item\">\r\n                        <a><img src=\"http://192.168.0.8:8080/FH-WEB3/uploadFiles/uploadImgs/20171116/38b7d8147cf34f9d845e36c85dc8609e.jpg\" alt=\"技术团队\"></a>\r\n                    </div>\r\n                    <div class=\"latest-project-item\">\r\n                        <a><img src=\"http://192.168.0.8:8080/FH-WEB3/uploadFiles/uploadImgs/20171116/6824ff8ab8c945689f422fdd85f5a664.jpg\" alt=\"技术团队\"></a>\r\n                    </div>\r\n                    \r\n                </div>-->\r\n            </div>\r\n            <div class=\"four columns\">\r\n                <h3>联系信息</h3>\r\n                <ul class=\"list contact\" style=\"margin-bottom: 15px;\">\r\n                    <li class=\"contact-address\">\r\n                        <i class=