INSERT INTO `sys_codeeditor` VALUES ('adaca6d9343b41128a96120364e44bc4', 'createHtml', 'indexTemplate', '2018-05-29 15:07:58', '<!DOCTYPE html>\r\n<html>\r\n\r\n<head>\r\n    <meta charset=\"UTF-8\">\r\n    <title>${TITLE}</title>\r\n    <link rel=\"stylesheet\" type=\"text/css\" href=\"fh_static_1/css/bootstrap.min.css\" />\r\n    <link rel=\"stylesheet\" type=\"text/css\" href=\"fh_static_1/css/style1.css\" />\r\n    <script type=\"text/javascript\" src=\"fh_static_1/js/jquery-1.10.2.js\"></script>\r\n    <script src=\"fh_static_1/js/bootstrap.min.js\"></script>\r\n    <script src=\"fh_static_1/js/script.js\"></script>\r\n</head>\r\n\r\n<body>\r\n<!--导航部分-->\r\n<nav class=\"navbar\">\r\n    <div class=\"container\">\r\n        <!-- Brand and toggle get grouped for better mobile display -->\r\n        <div class=\"navbar-header\">\r\n            <button type=\"button\" class=\"navbar-toggle collapsed\" data-toggle=\"collapse\" data-target=\"#bs-example-navbar-collapse-1\" aria-expanded=\"false\">\r\n                <span class=\"sr-only\">Toggle navigation</span>\r\n                <span class=\"icon-bar\"></span>\r\n                <span class=\"icon-bar\"></span>\r\n                <span class=\"icon-bar\"></span>\r\n            </button>\r\n            <a class=\"navbar-brand\" href=\"#\">\r\n                <img src=\"fh_static_1/images/logo.png\" alt=\"河南大岸信息技术有限公司\" title=\"河南大岸信息技术有限公司\" />\r\n            </a>\r\n        </div>\r\n\r\n        <div class=\"collapse navbar-collapse\" id=\"bs-example-navbar-collapse-1\">\r\n            <ul class=\"nav navbar-nav\">\r\n                <li class=\"active\">\r\n                    <a href=\"index.html\">首页</a>\r\n                </li>\r\n                <li>\r\n                    <a href=\"webaboutus.html\">公司简介</a>\r\n                </li>\r\n                <li>\r\n                    <a href=\"webproduct.html\">产品中心</a>\r\n                </li>\r\n                <li>\r\n                    <a href=\"webnews.html\">新闻中心</a>\r\n                </li>\r\n                <li>\r\n                    <a href=\"websolution.html\">解决方案</a>\r\n                </li>\r\n                <li>\r\n                    <a href=\"webcooperation.html\">合作共赢</a>\r\n                </li>\r\n                <li>\r\n                    <a href=\"webcontact.html\">联系我们</a>\r\n                </li>\r\n            </ul>\r\n\r\n        </div>\r\n    </div>\r\n</nav>\r\n\r\n<!--轮播图-->\r\n<div id=\"carousel-example-generic\" class=\"carousel slide\" data-ride=\"carousel\">\r\n    <!-- Indicators -->\r\n    <ol class=\"carousel-indicators\">\r\n        <li data-target=\"#carousel-example-generic\" data-slide-to=\"0\" class=\"active\"></li>\r\n        <li data-target=\"#carousel-example-generic\" data-slide-to=\"1\"></li>\r\n        <li data-target=\"#carousel-example-generic\" data-slide-to=\"2\"></li>\r\n        <li data-target=\"#carousel-example-generic\" data-slide-to=\"3\"></li>\r\n        <li data-target=\"#carousel-example-generic\" data-slide-to=\"4\"></li>\r\n    </ol>\r\n\r\n    <!-- Wrapper for slides -->\r\n    <div class=\"carousel-inner\" role=\"listbox\">\r\n        <div class=\"item active\" >\r\n            <img src=\"${IMG_1_0}\" />\r\n\r\n        </div>\r\n        <div class=\"item\">\r\n            <img src=\"${IMG_1_1}\" />\r\n\r\n        </div>\r\n        <div class=\"item\">\r\n            <img src=\"${IMG_1_2}\" />\r\n\r\n        </div>\r\n        <div class=\"item\">\r\n            <img src=\"${IMG_1_3}\" />\r\n\r\n        </div>\r\n        <div class=\"item\">\r\n            <img src=\"${IMG_1_4}\" />\r\n\r\n        </div>\r\n\r\n    </div>\r\n\r\n    <!-- Controls -->\r\n    <a class=\"left carousel-control\" href=\"#carousel-example-generic\" role=\"button\" data-slide=\"prev\">\r\n        <span class=\"glyphicon glyphicon-chevron-left\" aria-hidden=\"true\"></span>\r\n        <span class=\"sr-only\">Previous</span>\r\n    </a>\r\n    <a class=\"right carousel-control\" href=\"#carousel-example-generic\" role=\"button\" data-slide=\"next\">\r\n        <span class=\"glyphicon glyphicon-chevron-right\" aria-hidden=\"true\"></span>\r\n        <span class=\"sr-only\">Next</span>\r\n    </a>\r\n</div>\r\n\r\n<!--公司优势-->\r\n<div class=\"container-fluid icon_wrap padding60\">\r\n    <div class=\"h2 index_title text-center\">\r\n    ${TITLE1}\r\n        <span class=\"line\"></span>\r\n        <p>${TITLE2}</p>\r\n\r\n    </div>\r\n    <div class=\"container\">\r\n        <div class=\"row icon_box_main padding_top30\">\r\n            <div class=\"col-md-3 text-center icon_box\">\r\n						<span>\r\n							<img src=\"fh_static_1/images/11.png\" />\r\n						</span>\r\n                <h4>有效积累客户</h4>\r\n                <p>\r\n                    资料分门别类保存、重复过滤防止撞客、多种条件快捷查询、永不丢失\r\n                </p>\r\n            </div>\r\n\r\n            <div class=\"col-md-3 text-center icon_box\">\r\n						<span>\r\n							<img src=\"fh_static_1/images/12.png\" />\r\n						</span>\r\n                <h4>高效团队协作</h4>\r\n                <p>\r\n                    成员间共享协作，数据实时同步，工作效率大大提高\r\n                </p>\r\n            </div>\r\n\r\n            <div class=\"col-md-3 text-center icon_box\">\r\n						<span>\r\n							<img src=\"fh_static_1/images/13.png\" />\r\n						</span>\r\n                <h4>提高销售</h4>\r\n                <p>\r\n                    全信息化的管理，数据清晰，带来销售业绩的增长\r\n                </p>\r\n            </div>\r\n\r\n            <div class=\"col-md-3 text-center icon_box\">\r\n						<span>\r\n							<img src=\"fh_static_1/images/14.png\" />\r\n						</span>\r\n                <h4>数据分析</h4>\r\n                <p>\r\n                    清晰的统计报表，所有客户状态、销售数据、业绩排行一目了然\r\n                </p>\r\n            </div>\r\n\r\n        </div>\r\n    </div>\r\n</div>\r\n\r\n<!--公司简介-->\r\n<div class=\"container-fluid about_wrap padding60\">\r\n    <div class=\"h2 index_title text-center\">\r\n        公司简介\r\n        <span class=\"line\"></span>\r\n        <p>专注于解决企事业单位设备资产管理方面存在的问题</p>\r\n    </div>\r\n\r\n    <div class=\"container index_about_main padding_top30\">\r\n        <div class=\"row\">\r\n            <div class=\"col-md-6 index_about_main_left\">\r\n                <p>\r\n                    河南大岸信息技术有限公司，创建于2012年，专注于企事业单位设备资产管理方面存在的问题， 提供企业设备资产全生命周期管理解决方案和设备维护管理系统的实施服务。我们的自主产品DA-EAM系统， 是参考资深行业专家的设计理念和我们多年设备资产管理系统现场实施经验，总结开发的一套设备资产全生命周期 管理系统，拥有多项著作权证书，完全自主产权。适合企事业单位和工厂使用，可以获得量化的收益，还可以自由选择 部署在云服务器或本地服务器。另外，我们拥有稳定的技术开发团队，成熟的实施服务体系，可以提供软硬一体的产品定制开发， 移动应用APP、微信公众号、微信小程序的开发和后产品的运维服务......\r\n\r\n                </p>\r\n                <div>\r\n                    <a href=\"#\" class=\"btn btn-small btn-primary\">查看更多>></a>\r\n                </div>\r\n            </div>\r\n            <div class=\"col-md-6 index_about_main_right\">\r\n						<span>\r\n							<img src=\"fh_static_1/images/DA_system.jpg.jpg\" />\r\n						</span>\r\n            </div>\r\n        </div>\r\n    </div>\r\n</div>\r\n\r\n<!--产品中心-->\r\n\r\n<div class=\"pro_wrap container-fluid padding60\">\r\n\r\n    <div class=\"h2 index_title text-center\">\r\n        产品中心\r\n        <span class=\"line\"></span>\r\n        <p>专注于解决企事业单位设备资产管理方面存在的问题</p>\r\n    </div>\r\n\r\n    <div class=\"container padding_top30\">\r\n        <div class=\"row\">\r\n            <div class=\"col-md-3 pro_box\">\r\n                <a href=\"#\">\r\n                    <div class=\"pro_img_box\">\r\n                        <img src=\"fh_static_1/images/1.jpg\" />\r\n                    </div>\r\n                    <p>产品名称</p>\r\n                </a>\r\n            </div>\r\n\r\n            <div class=\"col-md-3 pro_box\">\r\n                <a href=\"#\">\r\n                    <div class=\"pro_img_box\">\r\n                        <img src=\"fh_static_1/images/1.jpg\" />\r\n                    </div>\r\n                    <p>产品名称</p>\r\n                </a>\r\n            </div>\r\n\r\n            <div class=\"col-md-3 pro_box\">\r\n                <a href=\"#\">\r\n                    <div class=\"pro_img_box\">\r\n                        <img src=\"fh_static_1/images/1.jpg\" />\r\n                    </div>\r\n                    <p>产品名称</p>\r\n                </a>\r\n            </div>\r\n\r\n            <div class=\"col-md-3 pro_box\">\r\n                <a href=\"#\">\r\n                    <div class=\"pro_img_box\">\r\n                        <img src=\"fh_static_1/images/1.jpg\" />\r\n                    </div>\r\n                    <p>产品名称</p>\r\n                </a>\r\n            </div>\r\n\r\n        </div>\r\n    </div>\r\n\r\n    <div class=\"text-center\">\r\n        <a class=\"btn btn-large btn-primary\">查看更多>></a>\r\n    </div>\r\n\r\n</div>\r\n\r\n<!--首页新闻中心-->\r\n<div class=\"container-fluid news_wrap padding60\">\r\n    <div class=\"h2 index_title text-center\">\r\n        行业新闻\r\n        <span class=\"line\"></span>\r\n        <p>专注于解决企事业单位设备资产管理方面存在的问题</p>\r\n    </div>\r\n\r\n    <div class=\"container padding_top30\">\r\n        <div class=\"row\">\r\n            <div class=\"col-md-6 index_news_left\">\r\n						<span>\r\n							<img src=\"fh_static_1/images/feature2.jpg\" />\r\n						</span>\r\n            </div>\r\n            <div class=\"col-md-6 index_news_right\">\r\n                <ul>\r\n                    <li>\r\n                        <a href=\"#\">\r\n									<span>\r\n										<p class=\"date_year\">2018-5</p>\r\n										<p class=\"date_day\">27</p>\r\n									</span>\r\n                            <div>\r\n                                <h4>这是条很长很长的新闻标题这是条很长很长的新闻标题这是条很长很长的新闻标题</h4>\r\n                                <p>2018年是协同市场发展面临新机遇的一年，面对云计算、大数据、人工智能等新兴技术的推动， 中国的经济发展走向数字化转型，在此趋势下，中国的企事业组织纷纷进行数字化转型探索，作 为连接人与组织的高绩效运营平台，协同管理平台也随之越来越被关注和重视，成为组织信息化的基础设施\r\n                                </p>\r\n                            </div>\r\n                        </a>\r\n                    </li>\r\n                    <li>\r\n                        <a href=\"#\">\r\n									<span>\r\n										<p class=\"date_year\">2018-5</p>\r\n										<p class=\"date_day\">27</p>\r\n									</span>\r\n                            <div>\r\n                                <h4>这是条很长很长的新闻标题这是条很长很长的新闻标题这是条很长很长的新闻标题</h4>\r\n                                <p>2018年是协同市场发展面临新机遇的一年，面对云计算、大数据、人工智能等新兴技术的推动， 中国的经济发展走向数字化转型，在此趋势下，中国的企事业组织纷纷进行数字化转型探索，作 为连接人与组织的高绩效运营平台，协同管理平台也随之越来越被关注和重视，成为组织信息化的基础设施\r\n                                </p>\r\n                            </div>\r\n                        </a>\r\n                    </li>\r\n                    <li>\r\n                        <a href=\"#\">\r\n									<span>\r\n										<p class=\"date_year\">2018-5</p>\r\n										<p class=\"date_day\">27</p>\r\n									</span>\r\n                            <div>\r\n                                <h4>这是条很长很长的新闻标题这是条很长很长的新闻标题这是条很长很长的新闻标题</h4>\r\n                                <p>2018年是协同市场发展面临新机遇的一年，面对云计算、大数据、人工智能等新兴技术的推动， 中国的经济发展走向数字化转型，在此趋势下，中国的企事业组织纷纷进行数字化转型探索，作 为连接人与组织的高绩效运营平台，协同管理平台也随之越来越被关注和重视，成为组织信息化的基础设施\r\n                                </p>\r\n                            </div>\r\n                        </a>\r\n                    </li>\r\n                </ul>\r\n            </div>\r\n        </div>\r\n    </div>\r\n\r\n    <div class=\"text-center padding_top30\">\r\n        <a class=\"btn btn-large btn-primary\">查看更多>></a>\r\n    </div>\r\n\r\n</div>\r\n\r\n<!--售后服务-->\r\n<div class=\"container-fluid service_wrap padding60\">\r\n    <div class=\"h2 index_title text-center\">\r\n        售后服务\r\n        <span class=\"line\"></span>\r\n        <p>专注于解决企事业单位设备资产管理方面存在的问题</p>\r\n    </div>\r\n\r\n    <div class=\"container\">\r\n        <div class=\"index_service_main clearfix padding_top30 row\">\r\n\r\n            <div class=\" index_service_main_box col-md-3\">\r\n                <div class=\"service_main_box_img text-center\">\r\n							<span>\r\n				       		<img   src=\"fh_static_1/images/s1.png\">\r\n				        </span>\r\n                </div>\r\n                <p class=\"service_main_box_title text-center\">检查维护</p>\r\n                <div class=\"service_main_box_line\">\r\n                    <span></span>\r\n                </div>\r\n                <div class=\"service_main_box_summary text-center\">\r\n                    定期检查和维护应按照建筑的要求对中压配电盘进行定期检查和维护\r\n                </div>\r\n            </div>\r\n\r\n            <div class=\" index_service_main_box col-md-3\">\r\n                <div class=\"service_main_box_img text-center\">\r\n							<span>\r\n				       		<img   src=\"fh_static_1/images/s2.png\">\r\n				        </span>\r\n                </div>\r\n                <p class=\"service_main_box_title text-center\">电话咨询</p>\r\n                <div class=\"service_main_box_line\">\r\n                    <span></span>\r\n                </div>\r\n                <div class=\"service_main_box_summary text-center\">\r\n                    热线以方便、快捷、保密等特点提供服务，咨询服务的一种扩展和延伸。\r\n                </div>\r\n            </div>\r\n\r\n            <div class=\" index_service_main_box col-md-3\">\r\n                <div class=\"service_main_box_img text-center\">\r\n							<span>\r\n				       		<img   src=\"fh_static_1/images/s3.png\">\r\n				        </span>\r\n                </div>\r\n                <p class=\"service_main_box_title text-center\">长时在线</p>\r\n                <div class=\"service_main_box_line\">\r\n                    <span></span>\r\n                </div>\r\n                <div class=\"service_main_box_summary text-center\">\r\n                    拥有普通话、英语座席，24小时客户服务热线。\r\n                </div>\r\n            </div>\r\n\r\n            <div class=\" index_service_main_box col-md-3\">\r\n                <div class=\"service_main_box_img text-center\">\r\n							<span>\r\n				       		<img   src=\"fh_static_1/images/s4.png\">\r\n				        </span>\r\n                </div>\r\n                <p class=\"service_main_box_title text-center\">诚信合作</p>\r\n                <div class=\"service_main_box_line\">\r\n                    <span></span>\r\n                </div>\r\n                <div class=\"service_main_box_summary text-center\">\r\n                    遵循诚信、公平、互利的合作原则，是合作共赢的根本保证。\r\n                </div>\r\n            </div>\r\n\r\n        </div>\r\n\r\n    </div>\r\n\r\n</div>\r\n\r\n<!--友情链接-->\r\n\r\n<div class=\"friendLink_wrap container-fluid padding60\">\r\n    <div class=\"h2 index_title text-center\">\r\n        合作客户\r\n        <span class=\"line\"></span>\r\n        <p>更多客户的不二选择</p>\r\n    </div>\r\n    <div class=\"row padding_top30\">\r\n        <ul class=\"clearfix\">\r\n            <li class=\"col-md-2\">\r\n                <a>\r\n                    <img src=\"fh_static_1/images/l1.jpg\" />\r\n                </a>\r\n            </li>\r\n            <li class=\"col-md-2\">\r\n                <a>\r\n                    <img src=\"fh_static_1/images/l2.jpg\" />\r\n                </a>\r\n            </li>\r\n            <li class=\"col-md-2\">\r\n                <a>\r\n                    <img src=\"fh_static_1/images/l3.jpg\" />\r\n                </a>\r\n            </li>\r\n            <li class=\"col-md-2\">\r\n                <a>\r\n                    <img src=\"fh_static_1/images/l4.jpg\" />\r\n                </a>\r\n            </li>\r\n            <li class=\"col-md-2\">\r\n                <a>\r\n                    <img src=\"fh_static_1/images/l5.jpg\" />\r\n                </a>\r\n            </li>\r\n            <li class=\"col-md-2\">\r\n                <a>\r\n                    <img src=\"fh_static_1/images/l6.jpg\" />\r\n                </a>\r\n            </li>\r\n            <li class=\"col-md-2\">\r\n                <a>\r\n                    <img src=\"fh_static_1/images/l1.jpg\" />\r\n                </a>\r\n            </li>\r\n            <li class=\"col-md-2\">\r\n                <a>\r\n                    <img src=\"fh_static_1/images/l2.jpg\" />\r\n                </a>\r\n            </li>\r\n            <li class=\"col-md-2\">\r\n                <a>\r\n                    <img src=\"fh_static_1/images/l3.jpg\" />\r\n                </a>\r\n            </li>\r\n            <li class=\"col-md-2\">\r\n                <a>\r\n                    <img src=\"fh_static_1/images/l4.jpg\" />\r\n                </a>\r\n            </li>\r\n            <li class=\"col-md-2\">\r\n                <a>\r\n                    <img src=\"fh_static_1/images/l5.jpg\" />\r\n                </a>\r\n            </li>\r\n            <li class=\"col-md-2\">\r\n                <a>\r\n                    <img src=\"fh_static_1/images/l6.jpg\" />\r\n                </a>\r\n            </li>\r\n        </ul>\r\n    </div>\r\n\r\n</div>\r\n\r\n<!--底部-->\r\n<div class=\"foot text-center\">\r\n    <strong>\r\n        <a href=\"http://www.miibeian.gov.cn\" target=\"_blank\" rel=\"nofollow\">\r\n            <span>B2-20090055-1 </span>\r\n        </a> |\r\n        <a href=\"/index.html\">\r\n            <span>河南大岸信息技术有限公司</span>\r\n        </a>\r\n\r\n    </strong>\r\n    <br> 通讯地址：\r\n    <span>郑州市高新区升龙有一城B座23楼635室</span> &nbsp;&nbsp;&nbsp;&nbsp;联系人：\r\n    <span>段菲</span> &nbsp;&nbsp;&nbsp;&nbsp;固定电话：\r\n    <span>0371-61318009</span> &nbsp;&nbsp;&nbsp;移动电话：\r\n    <span>13253310008</span>\r\n</div>\r\n</body>\r\n\r\n</html>');
INSERT INTO `sys_codeeditor` VALUES ('b64dee317fa64210a9fc2a3904dc1cfa', 'createHtml', 'solutionTemplate', '2018-06-06 16:54:26', '<!DOCTYPE html>\n<html>\n\n<head>\n    <meta charset=\"UTF-8\">\n    <title>${TITLE}</title>\n    <link rel=\"stylesheet\" type=\"text/css\" href=\"fh_static_1/css/bootstrap.min.css\" />\n    <link rel=\"stylesheet\" type=\"text/css\" href=\"fh_static_1/css/style1.css\" />\n    <script type=\"text/javascript\" src=\"fh_static_1/js/jquery-1.10.2.js\"></script>\n    <script src=\"fh_static_1/js/bootstrap.min.js\"></script>\n    <script src=\"fh_static_1/js/script.js\"></script>\n</head>\n\n<body>\n<!--导航部分-->\n<!-- header 包含导航菜单 -->\n	<#include \"headerTemplate.ftl\">\n<!-- header 包含导航菜单 -->\n<!--轮播图-->\n<div id=\"carousel-example-generic\" class=\"carousel slide\" data-ride=\"carousel\">\n    <!-- Indicators -->\n    <ol class=\"carousel-indicators\">\n        <li data-target=\"#carousel-example-generic\" data-slide-to=\"0\" class=\"active\"></li>\n        <li data-target=\"#carousel-example-generic\" data-slide-to=\"1\"></li>\n        <li data-target=\"#carousel-example-generic\" data-slide-to=\"2\"></li>\n        <li data-target=\"#carousel-example-generic\" data-slide-to=\"3\"></li>\n        <li data-target=\"#carousel-example-generic\" data-slide-to=\"4\"></li>\n        <li data-target=\"#carousel-example-generic\" data-slide-to=\"5\"></li>\n    </ol>\n\n    <!-- Wrapper for slides -->\n    <div class=\"carousel-inner\" role=\"listbox\">\n        <div class=\"item active\" >\n            <img src=\"${IMG_1_0}\" />\n\n        </div>\n        <div class=\"item\">\n            <img src=\"${IMG_1_1}\" />\n\n        </div>\n        <div class=\"item\">\n            <img src=\"${IMG_1_2}\" />\n\n        </div>\n        <div class=\"item\" >\n            <img src=\"${IMG_1_3}\" />\n\n        </div>\n        <div class=\"item\">\n            <img src=\"${IMG_1_4}\" />\n\n        </div>\n        <div class=\"item\">\n            <img src=\"${IMG_1_5}\" />\n\n        </div>\n    </div>\n\n    <!-- Controls -->\n    <a class=\"left carousel-control\" href=\"#carousel-example-generic\" role=\"button\" data-slide=\"prev\">\n        <span class=\"glyphicon glyphicon-chevron-left\" aria-hidden=\"true\"></span>\n        <span class=\"sr-only\">Previous</span>\n    </a>\n    <a class=\"right carousel-control\" href=\"#carousel-example-generic\" role=\"button\" data-slide=\"next\">\n        <span class=\"glyphicon glyphicon-chevron-right\" aria-hidden=\"true\"></span>\n        <span class=\"sr-only\">Next</span>\n    </a>\n</div>\n<!--公司简介-->\n<div class=\"container about_content_main padding60\">\n    <div class=\"content_title\">解决方案</div>\n    <div class=\"about_content padding_top30\">\n        <h4>解决方案</h4>\n        <p>\n            ${ABOUTUS}\n        </p>\n\n    </div>\n</div>\n\n<!-- footer 包含底部 -->\n	<#include \"footerTemplate.ftl\">\n<!-- footer 包含底部  -->\n</body>\n\n</html>\n');
INSERT INTO `sys_codeeditor` VALUES ('baa8129f4e3e45b9ba09d15d42f5fce7', 'createHtml', 'indexTemplate', '2018-05-29 09:59:35', '<!DOCTYPE html>\r\n<html>\r\n\r\n<head>\r\n    <meta charset=\"UTF-8\">\r\n    <title>${TITLE}</title>\r\n    <link rel=\"stylesheet\" type=\"text/css\" href=\"fh_static_1/css/bootstrap.min.css\" />\r\n    <link rel=\"stylesheet\" type=\"text/css\" href=\"fh_static_1/css/style1.css\" />\r\n    <script type=\"text/javascript\" src=\"fh_static_1/js/jquery-1.10.2.js\"></script>\r\n    <script src=\"fh_static_1/js/bootstrap.min.js\"></script>\r\n    <script src=\"fh_static_1/js/script.js\"></script>\r\n</head>\r\n\r\n<body>\r\n<!--导航部分-->\r\n<nav class=\"navbar\">\r\n    <div class=\"container\">\r\n        <!-- Brand and toggle get grouped for better mobile display -->\r\n        <div class=\"navbar-header\">\r\n            <button type=\"button\" class=\"navbar-toggle collapsed\" data-toggle=\"collapse\" data-target=\"#bs-example-navbar-collapse-1\" aria-expanded=\"false\">\r\n                <span class=\"sr-only\">Toggle navigation</span>\r\n                <span class=\"icon-bar\"></span>\r\n                <span class=\"icon-bar\"></span>\r\n                <span class=\"icon-bar\"></span>\r\n            </button>\r\n            <a class=\"navbar-brand\" href=\"#\">\r\n                <img src=\"fh_static_1/images/logo.png\" alt=\"河南大岸信息技术有限公司\" title=\"河南大岸信息技术有限公司\" />\r\n            </a>\r\n        </div>\r\n\r\n        <div class=\"collapse navbar-collapse\" id=\"bs-example-navbar-collapse-1\">\r\n            <ul class=\"nav navbar-nav\">\r\n                <li class=\"active\">\r\n                    <a href=\"index.html\">首页</a>\r\n                </li>\r\n                <li>\r\n                    <a href=\"webaboutus.html\">公司简介</a>\r\n                </li>\r\n                <li>\r\n                    <a href=\"webproduct.html\">产品中心</a>\r\n                </li>\r\n                <li>\r\n                    <a href=\"webnews.html\">新闻中心</a>\r\n                </li>\r\n                <li>\r\n                    <a href=\"websolution.html\">解决方案</a>\r\n                </li>\r\n                <li>\r\n                    <a href=\"webcooperation.html\">合作共赢</a>\r\n                </li>\r\n                <li>\r\n                    <a href=\"webcontact.html\">联系我们</a>\r\n                </li>\r\n            </ul>\r\n\r\n        </div>\r\n    </div>\r\n</nav>\r\n\r\n<!--轮播图-->\r\n<div id=\"carousel-example-generic\" class=\"carousel slide\" data-ride=\"carousel\">\r\n    <!-- Indicators -->\r\n    <ol class=\"carousel-indicators\">\r\n        <li data-target=\"#carousel-example-generic\" data-slide-to=\"0\" class=\"active\"></li>\r\n        <li data-target=\"#carousel-example-generic\" data-slide-to=\"1\"></li>\r\n        <li data-target=\"#carousel-example-generic\" data-slide-to=\"2\"></li>\r\n    </ol>\r\n\r\n    <!-- Wrapper for slides -->\r\n    <div class=\"carousel-inner\" role=\"listbox\">\r\n        <div class=\"item active\">\r\n            <img src=\"${IMG10}\" />\r\n\r\n        </div>\r\n        <div class=\"item\">\r\n            <img src=\"${IMG11}\" />\r\n\r\n        </div>\r\n        <div class=\"item\">\r\n            <img src=\"${IMG12}\" />\r\n\r\n        </div>\r\n        <div class=\"item\">\r\n            <img src=\"${IMG13}\" />\r\n\r\n        </div>\r\n        <div class=\"item\">\r\n            <img src=\"${IMG14}\" />\r\n\r\n        </div>\r\n\r\n    </div>\r\n\r\n    <!-- Controls -->\r\n    <a class=\"left carousel-control\" href=\"#carousel-example-generic\" role=\"button\" data-slide=\"prev\">\r\n        <span class=\"glyphicon glyphicon-chevron-left\" aria-hidden=\"true\"></span>\r\n        <span class=\"sr-only\">Previous</span>\r\n    </a>\r\n    <a class=\"right carousel-control\" href=\"#carousel-example-generic\" role=\"button\" data-slide=\"next\">\r\n        <span class=\"glyphicon glyphicon-chevron-right\" aria-hidden=\"true\"></span>\r\n        <span class=\"sr-only\">Next</span>\r\n    </a>\r\n</div>\r\n\r\n<!--公司优势-->\r\n<div class=\"container-fluid icon_wrap padding60\">\r\n    <div class=\"h2 index_title text-center\">\r\n        我们能为您做什么\r\n        <span class=\"line\"></span>\r\n        <p>解决与企业密切相关的数据管理问题</p>\r\n\r\n    </div>\r\n    <div class=\"container\">\r\n        <div class=\"row icon_box_main padding_top30\">\r\n            <div class=\"col-md-3 text-center icon_box\">\r\n						<span>\r\n							<img src=\"fh_static_1/images/11.png\" />\r\n						</span>\r\n                <h4>有效积累客户</h4>\r\n                <p>\r\n                    资料分门别类保存、重复过滤防止撞客、多种条件快捷查询、永不丢失\r\n                </p>\r\n            </div>\r\n\r\n            <div class=\"col-md-3 text-center icon_box\">\r\n						<span>\r\n							<img src=\"fh_static_1/images/12.png\" />\r\n						</span>\r\n                <h4>高效团队协作</h4>\r\n                <p>\r\n                    成员间共享协作，数据实时同步，工作效率大大提高\r\n                </p>\r\n            </div>\r\n\r\n            <div class=\"col-md-3 text-center icon_box\">\r\n						<span>\r\n							<img src=\"fh_static_1/images/13.png\" />\r\n						</span>\r\n                <h4>提高销售</h4>\r\n                <p>\r\n                    全信息化的管理，数据清晰，带来销售业绩的增长\r\n                </p>\r\n            </div>\r\n\r\n            <div class=\"col-md-3 text-center icon_box\">\r\n						<span>\r\n							<img src=\"fh_static_1/images/14.png\" />\r\n						</span>\r\n                <h4>数据分析</h4>\r\n                <p>\r\n                    清晰的统计报表，所有客户状态、销售数据、业绩排行一目了然\r\n                </p>\r\n            </div>\r\n\r\n        </div>\r\n    </div>\r\n</div>\r\n\r\n<!--公司简介-->\r\n<div class=\"container-fluid about_wrap padding60\">\r\n    <div class=\"h2 index_title text-center\">\r\n        公司简介\r\n        <span class=\"line\"></span>\r\n        <p>专注于解决企事业单位设备资产管理方面存在的问题</p>\r\n    </div>\r\n\r\n    <div class=\"container index_about_main padding_top30\">\r\n        <div class=\"row\">\r\n            <div class=\"col-md-6 index_about_main_left\">\r\n                <p>\r\n                    河南大岸信息技术有限公司，创建于2012年，专注于企事业单位设备资产管理方面存在的问题， 提供企业设备资产全生命周期管理解决方案和设备维护管理系统的实施服务。我们的自主产品DA-EAM系统， 是参考资深行业专家的设计理念和我们多年设备资产管理系统现场实施经验，总结开发的一套设备资产全生命周期 管理系统，拥有多项著作权证书，完全自主产权。适合企事业单位和工厂使用，可以获得量化的收益，还可以自由选择 部署在云服务器或本地服务器。另外，我们拥有稳定的技术开发团队，成熟的实施服务体系，可以提供软硬一体的产品定制开发， 移动应用APP、微信公众号、微信小程序的开发和后产品的运维服务......\r\n\r\n                </p>\r\n                <div>\r\n                    <a href=\"#\" class=\"btn btn-small btn-primary\">查看更多>></a>\r\n                </div>\r\n            </div>\r\n            <div class=\"col-md-6 index_about_main_right\">\r\n						<span>\r\n							<img src=\"fh_static_1/images/feature2.jpg\" />\r\n						</span>\r\n            </div>\r\n        </div>\r\n    </div>\r\n</div>\r\n\r\n<!--产品中心-->\r\n\r\n<div class=\"pro_wrap container-fluid padding60\">\r\n\r\n    <div class=\"h2 index_title text-center\">\r\n        产品中心\r\n        <span class=\"line\"></span>\r\n        <p>专注于解决企事业单位设备资产管理方面存在的问题</p>\r\n    </div>\r\n\r\n    <div class=\"container padding_top30\">\r\n        <div class=\"row\">\r\n            <div class=\"col-md-3 pro_box\">\r\n                <a href=\"#\">\r\n                    <div class=\"pro_img_box\">\r\n                        <img src=\"fh_static_1/images/1.jpg\" />\r\n                    </div>\r\n                    <p>产品名称</p>\r\n                </a>\r\n            </div>\r\n\r\n            <div class=\"col-md-3 pro_box\">\r\n                <a href=\"#\">\r\n                    <div class=\"pro_img_box\">\r\n                        <img src=\"fh_static_1/images/1.jpg\" />\r\n                    </div>\r\n                    <p>产品名称</p>\r\n                </a>\r\n            </div>\r\n\r\n            <div class=\"col-md-3 pro_box\">\r\n                <a href=\"#\">\r\n                    <div class=\"pro_img_box\">\r\n                        <img src=\"fh_static_1/images/1.jpg\" />\r\n                    </div>\r\n                    <p>产品名称</p>\r\n                </a>\r\n            </div>\r\n\r\n            <div class=\"col-md-3 pro_box\">\r\n                <a href=\"#\">\r\n                    <div class=\"pro_img_box\">\r\n                        <img src=\"fh_static_1/images/1.jpg\" />\r\n                    </div>\r\n                    <p>产品名称</p>\r\n                </a>\r\n            </div>\r\n\r\n        </div>\r\n    </div>\r\n\r\n    <div class=\"text-center\">\r\n        <a class=\"btn btn-large btn-primary\">查看更多>></a>\r\n    </div>\r\n\r\n</div>\r\n\r\n<!--首页新闻中心-->\r\n<div class=\"container-fluid news_wrap padding60\">\r\n    <div class=\"h2 index_title text-center\">\r\n        行业新闻\r\n        <span class=\"line\"></span>\r\n        <p>专注于解决企事业单位设备资产管理方面存在的问题</p>\r\n    </div>\r\n\r\n    <div class=\"container padding_top30\">\r\n        <div class=\"row\">\r\n            <div class=\"col-md-6 index_news_left\">\r\n						<span>\r\n							<img src=\"fh_static_1/images/feature2.jpg\" />\r\n						</span>\r\n            </div>\r\n            <div class=\"col-md-6 index_news_right\">\r\n                <ul>\r\n                    <li>\r\n                        <a href=\"#\">\r\n									<span>\r\n										<p class=\"date_year\">2018-5</p>\r\n										<p class=\"date_day\">27</p>\r\n									</span>\r\n                            <div>\r\n                                <h4>这是条很长很长的新闻标题这是条很长很长的新闻标题这是条很长很长的新闻标题</h4>\r\n                                <p>2018年是协同市场发展面临新机遇的一年，面对云计算、大数据、人工智能等新兴技术的推动， 中国的经济发展走向数字化转型，在此趋势下，中国的企事业组织纷纷进行数字化转型探索，作 为连接人与组织的高绩效运营平台，协同管理平台也随之越来越被关注和重视，成为组织信息化的基础设施\r\n                                </p>\r\n                            </div>\r\n                        </a>\r\n                    </li>\r\n                    <li>\r\n                        <a href=\"#\">\r\n									<span>\r\n										<p class=\"date_year\">2018-5</p>\r\n										<p class=\"date_day\">27</p>\r\n									</span>\r\n                            <div>\r\n                                <h4>这是条很长很长的新闻标题这是条很长很长的新闻标题这是条很长很长的新闻标题</h4>\r\n                                <p>2018年是协同市场发展面临新机遇的一年，面对云计算、大数据、人工智能等新兴技术的推动， 中国的经济发展走向数字化转型，在此趋势下，中国的企事业组织纷纷进行数字化转型探索，作 为连接人与组织的高绩效运营平台，协同管理平台也随之越来越被关注和重视，成为组织信息化的基础设施\r\n                                </p>\r\n                            </div>\r\n                        </a>\r\n                    </li>\r\n                    <li>\r\n                        <a href=\"#\">\r\n									<span>\r\n										<p class=\"date_year\">2018-5</p>\r\n										<p class=\"date_day\">27</p>\r\n									</span>\r\n                            <div>\r\n                                <h4>这是条很长很长的新闻标题这是条很长很长的新闻标题这是条很长很长的新闻标题</h4>\r\n                                <p>2018年是协同市场发展面临新机遇的一年，面对云计算、大数据、人工智能等新兴技术的推动， 中国的经济发展走向数字化转型，在此趋势下，中国的企事业组织纷纷进行数字化转型探索，作 为连接人与组织的高绩效运营平台，协同管理平台也随之越来越被关注和重视，成为组织信息化的基础设施\r\n                                </p>\r\n                            </div>\r\n                        </a>\r\n                    </li>\r\n                </ul>\r\n            </div>\r\n        </div>\r\n    </div>\r\n\r\n    <div class=\"text-center padding_top30\">\r\n        <a class=\"btn btn-large btn-primary\">查看更多>></a>\r\n    </div>\r\n\r\n</div>\r\n\r\n<!--售后服务-->\r\n<div class=\"container-fluid service_wrap padding60\">\r\n    <div class=\"h2 index_title text-center\">\r\n        售后服务\r\n        <span class=\"line\"></span>\r\n        <p>专注于解决企事业单位设备资产管理方面存在的问题</p>\r\n    </div>\r\n\r\n    <div class=\"container\">\r\n        <div class=\"index_service_main clearfix padding_top30 row\">\r\n\r\n            <div class=\" index_service_main_box col-md-3\">\r\n                <div class=\"service_main_box_img text-center\">\r\n							<span>\r\n				       		<img   src=\"fh_static_1/images/s1.png\">\r\n				        </span>\r\n                </div>\r\n                <p class=\"service_main_box_title text-center\">检查维护</p>\r\n                <div class=\"service_main_box_line\">\r\n                    <span></span>\r\n                </div>\r\n                <div class=\"service_main_box_summary text-center\">\r\n                    定期检查和维护应按照建筑的要求对中压配电盘进行定期检查和维护\r\n                </div>\r\n            </div>\r\n\r\n            <div class=\" index_service_main_box col-md-3\">\r\n                <div class=\"service_main_box_img text-center\">\r\n							<span>\r\n				       		<img   src=\"fh_static_1/images/s2.png\">\r\n				        </span>\r\n                </div>\r\n                <p class=\"service_main_box_title text-center\">电话咨询</p>\r\n                <div class=\"service_main_box_line\">\r\n                    <span></span>\r\n                </div>\r\n                <div class=\"service_main_box_summary text-center\">\r\n                    热线以方便、快捷、保密等特点提供服务，咨询服务的一种扩展和延伸。\r\n                </div>\r\n            </div>\r\n\r\n            <div class=\" index_service_main_box col-md-3\">\r\n                <div class=\"service_main_box_img text-center\">\r\n							<span>\r\n				       		<img   src=\"fh_static_1/images/s3.png\">\r\n				        </span>\r\n                </div>\r\n                <p class=\"service_main_box_title text-center\">长时在线</p>\r\n                <div class=\"service_main_box_line\">\r\n                    <span></span>\r\n                </div>\r\n                <div class=\"service_main_box_summary text-center\">\r\n                    拥有普通话、英语座席，24小时客户服务热线。\r\n                </div>\r\n            </div>\r\n\r\n            <div class=\" index_service_main_box col-md-3\">\r\n                <div class=\"service_main_box_img text-center\">\r\n							<span>\r\n				       		<img   src=\"fh_static_1/images/s4.png\">\r\n				        </span>\r\n                </div>\r\n                <p class=\"service_main_box_title text-center\">诚信合作</p>\r\n                <div class=\"service_main_box_line\">\r\n                    <span></span>\r\n                </div>\r\n                <div class=\"service_main_box_summary text-center\">\r\n                    遵循诚信、公平、互利的合作原则，是合作共赢的根本保证。\r\n                </div>\r\n            </div>\r\n\r\n        </div>\r\n\r\n    </div>\r\n\r\n</div>\r\n\r\n<!--友情链接-->\r\n\r\n<div class=\"friendLink_wrap container-fluid padding60\">\r\n    <div class=\"h2 index_title text-center\">\r\n        合作客户\r\n        <span class=\"line\"></span>\r\n        <p>更多客户的不二选择</p>\r\n    </div>\r\n    <div class=\"row padding_top30\">\r\n        <ul class=\"clearfix\">\r\n            <li class=\"col-md-2\">\r\n                <a>\r\n                    <img src=\"fh_static_1/images/l1.jpg\" />\r\n                </a>\r\n            </li>\r\n            <li class=\"col-md-2\">\r\n                <a>\r\n                    <img src=\"fh_static_1/images/l2.jpg\" />\r\n                </a>\r\n            </li>\r\n            <li class=\"col-md-2\">\r\n                <a>\r\n                    <img src=\"fh_static_1/images/l3.jpg\" />\r\n                </a>\r\n            </li>\r\n            <li class=\"col-md-2\">\r\n                <a>\r\n                    <img src=\"fh_static_1/images/l4.jpg\" />\r\n                </a>\r\n            </li>\r\n            <li class=\"col-md-2\">\r\n                <a>\r\n                    <img src=\"fh_static_1/images/l5.jpg\" />\r\n                </a>\r\n            </li>\r\n            <li class=\"col-md-2\">\r\n                <a>\r\n                    <img src=\"fh_static_1/images/l6.jpg\" />\r\n                </a>\r\n            </li>\r\n            <li class=\"col-md-2\">\r\n                <a>\r\n                    <img src=\"fh_static_1/images/l1.jpg\" />\r\n                </a>\r\n            </li>\r\n            <li class=\"col-md-2\">\r\n                <a>\r\n                    <img src=\"fh_static_1/images/l2.jpg\" />\r\n                </a>\r\n            </li>\r\n            <li class=\"col-md-2\">\r\n                <a>\r\n                    <img src=\"fh_static_1/images/l3.jpg\" />\r\n                </a>\r\n            </li>\r\n            <li class=\"col-md-2\">\r\n                <a>\r\n                    <img src=\"fh_static_1/images/l4.jpg\" />\r\n                </a>\r\n            </li>\r\n            <li class=\"col-md-2\">\r\n                <a>\r\n                    <img src=\"fh_static_1/images/l5.jpg\" />\r\n                </a>\r\n            </li>\r\n            <li class=\"col-md-2\">\r\n                <a>\r\n                    <img src=\"fh_static_1/images/l6.jpg\" />\r\n                </a>\r\n            </li>\r\n        </ul>\r\n    </div>\r\n\r\n</div>\r\n\r\n<!--底部-->\r\n<div class=\"foot text-center\">\r\n    <strong>\r\n        <a href=\"http://www.miibeian.gov.cn\" target=\"_blank\" rel=\"nofollow\">\r\n            <span>B2-20090055-1 </span>\r\n        </a> |\r\n        <a href=\"/index.html\">\r\n            <span>河南大岸信息技术有限公司</span>\r\n        </a>\r\n\r\n    </strong>\r\n    <br> 通讯地址：\r\n    <span>郑州市高新区升龙有一城B座23楼635室</span> &nbsp;&nbsp;&nbsp;&nbsp;联系人：\r\n    <span>段菲</span> &nbsp;&nbsp;&nbsp;&nbsp;固定电话：\r\n    <span>0371-61318009</span> &nbsp;&nbsp;&nbsp;移动电话：\r\n    <span>13253310008</span>\r\n</div>\r\n</body>\r\n\r\n</html>');
INSERT INTO `sys_codeeditor` VALUES ('c2635d3d42cb4c1bbf926396a8eaf946', 'createHtml', 'indexTemplate', '2018-05-29 08:47:30', '<!DOCTYPE html>\r\n<html>\r\n\r\n<head>\r\n    <meta charset=\"UTF-8\">\r\n    <title>${TITLE}</title>\r\n    <link rel=\"stylesheet\" type=\"text/css\" href=\"fh_static_1/css/bootstrap.min.css\" />\r\n    <link rel=\"stylesheet\" type=\"text/css\" href=\"fh_static_1/css/style1.css\" />\r\n    <script type=\"text/javascript\" src=\"fh_static_1/js/jquery-1.10.2.js\"></script>\r\n    <script src=\"fh_static_1/js/bootstrap.min.js\"></script>\r\n    <script src=\"fh_static_1/js/script.js\"></script>\r\n</head>\r\n\r\n<body>\r\n<!--导航部分-->\r\n<nav class=\"navbar\">\r\n    <div class=\"container\">\r\n        <!-- Brand and toggle get grouped for better mobile display -->\r\n        <div class=\"navbar-header\">\r\n            <button type=\"button\" class=\"navbar-toggle collapsed\" data-toggle=\"collapse\" data-target=\"#bs-example-navbar-collapse-1\" aria-expanded=\"false\">\r\n                <span class=\"sr-only\">Toggle navigation</span>\r\n                <span class=\"icon-bar\"></span>\r\n                <span class=\"icon-bar\"></span>\r\n                <span class=\"icon-bar\"></span>\r\n            </button>\r\n            <a class=\"navbar-brand\" href=\"#\">\r\n                <img src=\"fh_static_1/images/logo.png\" alt=\"河南大岸信息技术有限公司\" title=\"河南大岸信息技术有限公司\" />\r\n            </a>\r\n        </div>\r\n\r\n        <div class=\"collapse navbar-collapse\" id=\"bs-example-navbar-collapse-1\">\r\n            <ul class=\"nav navbar-nav\">\r\n                <li class=\"active\">\r\n                    <a href=\"index.html\">首页</a>\r\n                </li>\r\n                <li>\r\n                    <a href=\"webaboutus.html\">公司简介</a>\r\n                </li>\r\n                <li>\r\n                    <a href=\"webproduct.html\">产品中心</a>\r\n                </li>\r\n                <li>\r\n                    <a href=\"webnews.html\">新闻中心</a>\r\n                </li>\r\n                <li>\r\n                    <a href=\"websolution.html\">解决方案</a>\r\n                </li>\r\n                <li>\r\n                    <a href=\"webcooperation.html\">合作共赢</a>\r\n                </li>\r\n                <li>\r\n                    <a href=\"webcontact.html\">联系我们</a>\r\n                </li>\r\n            </ul>\r\n\r\n        </div>\r\n    </div>\r\n</nav>\r\n\r\n<!--轮播图-->\r\n<div id=\"carousel-example-generic\" class=\"carousel slide\" data-ride=\"carousel\">\r\n    <!-- Indicators -->\r\n    <ol class=\"carousel-indicators\">\r\n        <li data-target=\"#carousel-example-generic\" data-slide-to=\"0\" class=\"active\"></li>\r\n        <li data-target=\"#carousel-example-generic\" data-slide-to=\"1\"></li>\r\n        <li data-target=\"#carousel-example-generic\" data-slide-to=\"2\"></li>\r\n    </ol>\r\n\r\n    <!-- Wrapper for slides -->\r\n    <div class=\"carousel-inner\" role=\"listbox\">\r\n        <#list fieldList1 as var>\r\n            <li data-transition=\"boxfade\" data-slotamount=\"${var_index+1+1}\" data-masterspeed=\"300\">\r\n                <img src=\"${var[1]}\" alt=\"${var[0]}\">\r\n            </li>\r\n        </#list>\r\n\r\n    </div>\r\n\r\n    <!-- Controls -->\r\n    <a class=\"left carousel-control\" href=\"#carousel-example-generic\" role=\"button\" data-slide=\"prev\">\r\n        <span class=\"glyphicon glyphicon-chevron-left\" aria-hidden=\"true\"></span>\r\n        <span class=\"sr-only\">Previous</span>\r\n    </a>\r\n    <a class=\"right carousel-control\" href=\"#carousel-example-generic\" role=\"button\" data-slide=\"next\">\r\n        <span class=\"glyphicon glyphicon-chevron-right\" aria-hidden=\"true\"></span>\r\n        <span class=\"sr-only\">Next</span>\r\n    </a>\r\n</div>\r\n\r\n<!--公司优势-->\r\n<div class=\"container-fluid icon_wrap padding60\">\r\n    <div class=\"h2 index_title text-center\">\r\n        我们能为您做什么\r\n        <span class=\"line\"></span>\r\n        <p>解决与企业密切相关的数据管理问题</p>\r\n\r\n    </div>\r\n    <div class=\"container\">\r\n        <div class=\"row icon_box_main padding_top30\">\r\n            <div class=\"col-md-3 text-center icon_box\">\r\n						<span>\r\n							<img src=\"fh_static_1/images/11.png\" />\r\n						</span>\r\n                <h4>有效积累客户</h4>\r\n                <p>\r\n                    资料分门别类保存、重复过滤防止撞客、多种条件快捷查询、永不丢失\r\n                </p>\r\n            </div>\r\n\r\n            <div class=\"col-md-3 text-center icon_box\">\r\n						<span>\r\n							<img src=\"fh_static_1/images/12.png\" />\r\n						</span>\r\n                <h4>高效团队协作</h4>\r\n                <p>\r\n                    成员间共享协作，数据实时同步，工作效率大大提高\r\n                </p>\r\n            </div>\r\n\r\n            <div class=\"col-md-3 text-center icon_box\">\r\n						<span>\r\n							<img src=\"fh_static_1/images/13.png\" />\r\n						</span>\r\n                <h4>提高销售</h4>\r\n                <p>\r\n                    全信息化的管理，数据清晰，带来销售业绩的增长\r\n                </p>\r\n            </div>\r\n\r\n            <div class=\"col-md-3 text-center icon_box\">\r\n						<span>\r\n							<img src=\"fh_static_1/images/14.png\" />\r\n						</span>\r\n                <h4>数据分析</h4>\r\n                <p>\r\n                    清晰的统计报表，所有客户状态、销售数据、业绩排行一目了然\r\n                </p>\r\n            </div>\r\n\r\n        </div>\r\n    </div>\r\n</div>\r\n\r\n<!--公司简介-->\r\n<div class=\"container-fluid about_wrap padding60\">\r\n    <div class=\"h2 index_title text-center\">\r\n        公司简介\r\n        <span class=\"line\"></span>\r\n        <p>专注于解决企事业单位设备资产管理方面存在的问题</p>\r\n    </div>\r\n\r\n    <div class=\"container index_about_main padding_top30\">\r\n        <div class=\"row\">\r\n            <div class=\"col-md-6 index_about_main_left\">\r\n                <p>\r\n                    河南大岸信息技术有限公司，创建于2012年，专注于企事业单位设备资产管理方面存在的问题， 提供企业设备资产全生命周期管理解决方案和设备维护管理系统的实施服务。我们的自主产品DA-EAM系统， 是参考资深行业专家的设计理念和我们多年设备资产管理系统现场实施经验，总结开发的一套设备资产全生命周期 管理系统，拥有多项著作权证书，完全自主产权。适合企事业单位和工厂使用，可以获得量化的收益，还可以自由选择 部署在云服务器或本地服务器。另外，我们拥有稳定的技术开发团队，成熟的实施服务体系，可以提供软硬一体的产品定制开发， 移动应用APP、微信公众号、微信小程序的开发和后产品的运维服务......\r\n\r\n                </p>\r\n                <div>\r\n                    <a href=\"#\" class=\"btn btn-small btn-primary\">查看更多>></a>\r\n                </div>\r\n            </div>\r\n            <div class=\"col-md-6 index_about_main_right\">\r\n						<span>\r\n							<img src=\"fh_static_1/images/feature2.jpg\" />\r\n						</span>\r\n            </div>\r\n        </div>\r\n    </div>\r\n</div>\r\n\r\n<!--产品中心-->\r\n\r\n<div class=\"pro_wrap container-fluid padding60\">\r\n\r\n    <div class=\"h2 index_title text-center\">\r\n        产品中心\r\n        <span class=\"line\"></span>\r\n        <p>专注于解决企事业单位设备资产管理方面存在的问题</p>\r\n    </div>\r\n\r\n    <div class=\"container padding_top30\">\r\n        <div class=\"row\">\r\n            <div class=\"col-md-3 pro_box\">\r\n                <a href=\"#\">\r\n                    <div class=\"pro_img_box\">\r\n                        <img src=\"fh_static_1/images/1.jpg\" />\r\n                    </div>\r\n                    <p>产品名称</p>\r\n                </a>\r\n            </div>\r\n\r\n            <div class=\"col-md-3 pro_box\">\r\n                <a href=\"#\">\r\n                    <div class=\"pro_img_box\">\r\n                        <img src=\"fh_static_1/images/1.jpg\" />\r\n                    </div>\r\n                    <p>产品名称</p>\r\n                </a>\r\n            </div>\r\n\r\n            <div class=\"col-md-3 pro_box\">\r\n                <a href=\"#\">\r\n                    <div class=\"pro_img_box\">\r\n                        <img src=\"fh_static_1/images/1.jpg\" />\r\n                    </div>\r\n                    <p>产品名称</p>\r\n                </a>\r\n            </div>\r\n\r\n            <div class=\"col-md-3 pro_box\">\r\n                <a href=\"#\">\r\n                    <div class=\"pro_img_box\">\r\n                        <img src=\"fh_static_1/images/1.jpg\" />\r\n                    </div>\r\n                    <p>产品名称</p>\r\n                </a>\r\n            </div>\r\n\r\n        </div>\r\n    </div>\r\n\r\n    <div class=\"text-center\">\r\n        <a class=\"btn btn-large btn-primary\">查看更多>></a>\r\n    </div>\r\n\r\n</div>\r\n\r\n<!--首页新闻中心-->\r\n<div class=\"container-fluid news_wrap padding60\">\r\n    <div class=\"h2 index_title text-center\">\r\n        行业新闻\r\n        <span class=\"line\"></span>\r\n        <p>专注于解决企事业单位设备资产管理方面存在的问题</p>\r\n    </div>\r\n\r\n    <div class=\"container padding_top30\">\r\n        <div class=\"row\">\r\n            <div class=\"col-md-6 index_news_left\">\r\n						<span>\r\n							<img src=\"fh_static_1/images/feature2.jpg\" />\r\n						</span>\r\n            </div>\r\n            <div class=\"col-md-6 index_news_right\">\r\n                <ul>\r\n                    <li>\r\n                        <a href=\"#\">\r\n									<span>\r\n										<p class=\"date_year\">2018-5</p>\r\n										<p class=\"date_day\">27</p>\r\n									</span>\r\n                            <div>\r\n                                <h4>这是条很长很长的新闻标题这是条很长很长的新闻标题这是条很长很长的新闻标题</h4>\r\n                                <p>2018年是协同市场发展面临新机遇的一年，面对云计算、大数据、人工智能等新兴技术的推动， 中国的经济发展走向数字化转型，在此趋势下，中国的企事业组织纷纷进行数字化转型探索，作 为连接人与组织的高绩效运营平台，协同管理平台也随之越来越被关注和重视，成为组织信息化的基础设施\r\n                                </p>\r\n                            </div>\r\n                        </a>\r\n                    </li>\r\n                    <li>\r\n                        <a href=\"#\">\r\n									<span>\r\n										<p class=\"date_year\">2018-5</p>\r\n										<p class=\"date_day\">27</p>\r\n									</span>\r\n                            <div>\r\n                                <h4>这是条很长很长的新闻标题这是条很长很长的新闻标题这是条很长很长的新闻标题</h4>\r\n                                <p>2018年是协同市场发展面临新机遇的一年，面对云计算、大数据、人工智能等新兴技术的推动， 中国的经济发展走向数字化转型，在此趋势下，中国的企事业组织纷纷进行数字化转型探索，作 为连接人与组织的高绩效运营平台，协同管理平台也随之越来越被关注和重视，成为组织信息化的基础设施\r\n                                </p>\r\n                            </div>\r\n                        </a>\r\n                    </li>\r\n                    <li>\r\n                        <a href=\"#\">\r\n									<span>\r\n										<p class=\"date_year\">2018-5</p>\r\n										<p class=\"date_day\">27</p>\r\n									</span>\r\n                            <div>\r\n                                <h4>这是条很长很长的新闻标题这是条很长很长的新闻标题这是条很长很长的新闻标题</h4>\r\n                                <p>2018年是协同市场发展面临新机遇的一年，面对云计算、大数据、人工智能等新兴技术的推动， 中国的经济发展走向数字化转型，在此趋势下，中国的企事业组织纷纷进行数字化转型探索，作 为连接人与组织的高绩效运营平台，协同管理平台也随之越来越被关注和重视，成为组织信息化的基础设施\r\n                                </p>\r\n                            </div>\r\n                        </a>\r\n                    </li>\r\n                </ul>\r\n            </div>\r\n        </div>\r\n    </div>\r\n\r\n    <div class=\"text-center padding_top30\">\r\n        <a class=\"btn btn-large btn-primary\">查看更多>></a>\r\n    </div>\r\n\r\n</div>\r\n\r\n<!--售后服务-->\r\n<div class=\"container-fluid service_wrap padding60\">\r\n    <div class=\"h2 index_title text-center\">\r\n        售后服务\r\n        <span class=\"line\"></span>\r\n        <p>专注于解决企事业单位设备资产管理方面存在的问题</p>\r\n    </div>\r\n\r\n    <div class=\"container\">\r\n        <div class=\"index_service_main clearfix padding_top30 row\">\r\n\r\n            <div class=\" index_service_main_box col-md-3\">\r\n                <div class=\"service_main_box_img text-center\">\r\n							<span>\r\n				       		<img   src=\"fh_static_1/images/s1.png\">\r\n				        </span>\r\n                </div>\r\n                <p class=\"service_main_box_title text-center\">检查维护</p>\r\n                <div class=\"service_main_box_line\">\r\n                    <span></span>\r\n                </div>\r\n                <div class=\"service_main_box_summary text-center\">\r\n                    定期检查和维护应按照建筑的要求对中压配电盘进行定期检查和维护\r\n                </div>\r\n            </div>\r\n\r\n            <div class=\" index_service_main_box col-md-3\">\r\n                <div class=\"service_main_box_img text-center\">\r\n							<span>\r\n				       		<img   src=\"fh_static_1/images/s2.png\">\r\n				        </span>\r\n                </div>\r\n                <p class=\"service_main_box_title text-center\">电话咨询</p>\r\n                <div class=\"service_main_box_line\">\r\n                    <span></span>\r\n                </div>\r\n                <div class=\"service_main_box_summary text-center\">\r\n                    热线以方便、快捷、保密等特点提供服务，咨询服务的一种扩展和延伸。\r\n                </div>\r\n            </div>\r\n\r\n            <div class=\" index_service_main_box col-md-3\">\r\n                <div class=\"service_main_box_img text-center\">\r\n							<span>\r\n				       		<img   src=\"fh_static_1/images/s3.png\">\r\n				        </span>\r\n                </div>\r\n                <p class=\"service_main_box_title text-center\">长时在线</p>\r\n                <div class=\"service_main_box_line\">\r\n                    <span></span>\r\n                </div>\r\n                <div class=\"service_main_box_summary text-center\">\r\n                    拥有普通话、英语座席，24小时客户服务热线。\r\n                </div>\r\n            </div>\r\n\r\n            <div class=\" index_service_main_box col-md-3\">\r\n                <div class=\"service_main_box_img text-center\">\r\n							<span>\r\n				       		<img   src=\"fh_static_1/images/s4.png\">\r\n				        </span>\r\n                </div>\r\n                <p class=\"service_main_box_title text-center\">诚信合作</p>\r\n                <div class=\"service_main_box_line\">\r\n                    <span></span>\r\n                </div>\r\n                <div class=\"service_main_box_summary text-center\">\r\n                    遵循诚信、公平、互利的合作原则，是合作共赢的根本保证。\r\n                </div>\r\n            </div>\r\n\r\n        </div>\r\n\r\n    </div>\r\n\r\n</div>\r\n\r\n<!--友情链接-->\r\n\r\n<div class=\"friendLink_wrap container-fluid padding60\">\r\n    <div class=\"h2 index_title text-center\">\r\n        合作客户\r\n        <span class=\"line\"></span>\r\n        <p>更多客户的不二选择</p>\r\n    </div>\r\n    <div class=\"row padding_top30\">\r\n        <ul class=\"clearfix\">\r\n            <li class=\"col-md-2\">\r\n                <a>\r\n                    <img src=\"fh_static_1/images/l1.jpg\" />\r\n                </a>\r\n            </li>\r\n            <li class=\"col-md-2\">\r\n                <a>\r\n                    <img src=\"fh_static_1/images/l2.jpg\" />\r\n                </a>\r\n            </li>\r\n            <li class=\"col-md-2\">\r\n                <a>\r\n                    <img src=\"fh_static_1/images/l3.jpg\" />\r\n                </a>\r\n            </li>\r\n            <li class=\"col-md-2\">\r\n                <a>\r\n                    <img src=\"fh_static_1/images/l4.jpg\" />\r\n                </a>\r\n            </li>\r\n            <li class=\"col-md-2\">\r\n                <a>\r\n                    <img src=\"fh_static_1/images/l5.jpg\" />\r\n                </a>\r\n            </li>\r\n            <li class=\"col-md-2\">\r\n                <a>\r\n                    <img src=\"fh_static_1/images/l6.jpg\" />\r\n                </a>\r\n            </li>\r\n            <li class=\"col-md-2\">\r\n                <a>\r\n                    <img src=\"fh_static_1/images/l1.jpg\" />\r\n                </a>\r\n            </li>\r\n            <li class=\"col-md-2\">\r\n                <a>\r\n                    <img src=\"fh_static_1/images/l2.jpg\" />\r\n                </a>\r\n            </li>\r\n            <li class=\"col-md-2\">\r\n                <a>\r\n                    <img src=\"fh_static_1/images/l3.jpg\" />\r\n                </a>\r\n            </li>\r\n            <li class=\"col-md-2\">\r\n                <a>\r\n                    <img src=\"fh_static_1/images/l4.jpg\" />\r\n                </a>\r\n            </li>\r\n            <li class=\"col-md-2\">\r\n                <a>\r\n                    <img src=\"fh_static_1/images/l5.jpg\" />\r\n                </a>\r\n            </li>\r\n            <li class=\"col-md-2\">\r\n                <a>\r\n                    <img src=\"fh_static_1/images/l6.jpg\" />\r\n                </a>\r\n            </li>\r\n        </ul>\r\n    </div>\r\n\r\n</div>\r\n\r\n<!--底部-->\r\n<div class=\"foot text-center\">\r\n    <strong>\r\n        <a href=\"http://www.miibeian.gov.cn\" target=\"_blank\" rel=\"nofollow\">\r\n            <span>B2-20090055-1 </span>\r\n        </a> |\r\n        <a href=\"/index.html\">\r\n            <span>河南大岸信息技术有限公司</span>\r\n        </a>\r\n\r\n    </strong>\r\n    <br> 通讯地址：\r\n    <span>郑州市高新区升龙有一城B座23楼635室</span> &nbsp;&nbsp;&nbsp;&nbsp;联系人：\r\n    <span>段菲</span> &nbsp;&nbsp;&nbsp;&nbsp;固定电话：\r\n    <span>0371-61318009</span> &nbsp;&nbsp;&nbsp;移动电话：\r\n    <span>13253310008</span>\r\n</div>\r\n</body>\r\n\r\n</html>');
INSERT INTO `sys_codeeditor` VALUES ('c39f795a840748bdb7b5c221ffb2d962', 'createHtml', 'indexTemplate', '2018-05-28 15:16:36', '<!DOCTYPE html>\r\n<html>\r\n\r\n	<head>\r\n		<meta charset=\"UTF-8\">\r\n		<title>${TITLE}</title>\r\n		<link rel=\"stylesheet\" type=\"text/css\" href=\"fh_static_1/css/bootstrap.min.css\" />\r\n		<link rel=\"stylesheet\" type=\"text/css\" href=\"fh_static_1/css/style1.css\" />\r\n		<script type=\"text/javascript\" src=\"fh_static_1/js/jquery-1.10.2.js\"></script>\r\n		<script src=\"fh_static_1/js/bootstrap.min.js\"></script>\r\n		<script src=\"fh_static_1/js/script.js\"></script>\r\n	</head>\r\n\r\n	<body>\r\n		<!--导航部分-->\r\n		<nav class=\"navbar\">\r\n			<div class=\"container\">\r\n				<!-- Brand and toggle get grouped for better mobile display -->\r\n				<div class=\"navbar-header\">\r\n					<button type=\"button\" class=\"navbar-toggle collapsed\" data-toggle=\"collapse\" data-target=\"#bs-example-navbar-collapse-1\" aria-expanded=\"false\">\r\n			        <span class=\"sr-only\">Toggle navigation</span>\r\n			        <span class=\"icon-bar\"></span>\r\n			        <span class=\"icon-bar\"></span>\r\n			        <span class=\"icon-bar\"></span>\r\n			    </button>\r\n					<a class=\"navbar-brand\" href=\"#\">\r\n						<img src=\"fh_static_1/images/logo.png\" alt=\"河南大岸信息技术有限公司\" title=\"河南大岸信息技术有限公司\" />\r\n					</a>\r\n				</div>\r\n\r\n				<div class=\"collapse navbar-collapse\" id=\"bs-example-navbar-collapse-1\">\r\n					<ul class=\"nav navbar-nav\">\r\n						<li class=\"active\">\r\n							<a href=\"index.html\">首页</a>\r\n						</li>\r\n						<li>\r\n							<a href=\"webaboutus.html\">公司简介</a>\r\n						</li>\r\n						<li>\r\n							<a href=\"webproduct.html\">产品中心</a>\r\n						</li>\r\n						<li>\r\n							<a href=\"webnews.html\">新闻中心</a>\r\n						</li>\r\n						<li>\r\n							<a href=\"websolution.html\">解决方案</a>\r\n						</li>\r\n						<li>\r\n							<a href=\"webcooperation.html\">合作共赢</a>\r\n						</li>\r\n						<li>\r\n							<a href=\"webcontact.html\">联系我们</a>\r\n						</li>\r\n					</ul>\r\n\r\n				</div>\r\n			</div>\r\n		</nav>\r\n\r\n		<!--轮播图-->\r\n		<div id=\"carousel-example-generic\" class=\"carousel slide\" data-ride=\"carousel\">\r\n			<!-- Indicators -->\r\n			<ol class=\"carousel-indicators\">\r\n				<li data-target=\"#carousel-example-generic\" data-slide-to=\"0\" class=\"active\"></li>\r\n				<li data-target=\"#carousel-example-generic\" data-slide-to=\"1\"></li>\r\n				<li data-target=\"#carousel-example-generic\" data-slide-to=\"2\"></li>\r\n			</ol>\r\n\r\n			<!-- Wrapper for slides -->\r\n			<div class=\"carousel-inner\" role=\"listbox\">\r\n				<li data-transition=\"boxfade\" data-slotamount=\"${var_index+1+1}\" data-masterspeed=\"300\">\r\n						<img src=\"${var[1]}\" alt=\"${var[0]}\">\r\n					</li>\r\n\r\n			</div>\r\n\r\n			<!-- Controls -->\r\n			<a class=\"left carousel-control\" href=\"#carousel-example-generic\" role=\"button\" data-slide=\"prev\">\r\n				<span class=\"glyphicon glyphicon-chevron-left\" aria-hidden=\"true\"></span>\r\n				<span class=\"sr-only\">Previous</span>\r\n			</a>\r\n			<a class=\"right carousel-control\" href=\"#carousel-example-generic\" role=\"button\" data-slide=\"next\">\r\n				<span class=\"glyphicon glyphicon-chevron-right\" aria-hidden=\"true\"></span>\r\n				<span class=\"sr-only\">Next</span>\r\n			</a>\r\n		</div>\r\n\r\n		<!--公司优势-->\r\n		<div class=\"container-fluid icon_wrap padding60\">\r\n			<div class=\"h2 index_title text-center\">\r\n				我们能为您做什么\r\n				<span class=\"line\"></span>\r\n				<p>解决与企业密切相关的数据管理问题</p>\r\n\r\n			</div>\r\n			<div class=\"container\">\r\n				<div class=\"row icon_box_main padding_top30\">\r\n					<div class=\"col-md-3 text-center icon_box\">\r\n						<span>\r\n							<img src=\"fh_static_1/images/11.png\" />\r\n						</span>\r\n						<h4>有效积累客户</h4>\r\n						<p>\r\n							资料分门别类保存、重复过滤防止撞客、多种条件快捷查询、永不丢失\r\n						</p>\r\n					</div>\r\n\r\n					<div class=\"col-md-3 text-center icon_box\">\r\n						<span>\r\n							<img src=\"fh_static_1/images/12.png\" />\r\n						</span>\r\n						<h4>高效团队协作</h4>\r\n						<p>\r\n							成员间共享协作，数据实时同步，工作效率大大提高\r\n						</p>\r\n					</div>\r\n\r\n					<div class=\"col-md-3 text-center icon_box\">\r\n						<span>\r\n							<img src=\"fh_static_1/images/13.png\" />\r\n						</span>\r\n						<h4>提高销售</h4>\r\n						<p>\r\n							全信息化的管理，数据清晰，带来销售业绩的增长\r\n						</p>\r\n					</div>\r\n\r\n					<div class=\"col-md-3 text-center icon_box\">\r\n						<span>\r\n							<img src=\"fh_static_1/images/14.png\" />\r\n						</span>\r\n						<h4>数据分析</h4>\r\n						<p>\r\n							清晰的统计报表，所有客户状态、销售数据、业绩排行一目了然\r\n						</p>\r\n					</div>\r\n\r\n				</div>\r\n			</div>\r\n		</div>\r\n\r\n		<!--公司简介-->\r\n		<div class=\"container-fluid about_wrap padding60\">\r\n			<div class=\"h2 index_title text-center\">\r\n				公司简介\r\n				<span class=\"line\"></span>\r\n				<p>专注于解决企事业单位设备资产管理方面存在的问题</p>\r\n			</div>\r\n\r\n			<div class=\"container index_about_main padding_top30\">\r\n				<div class=\"row\">\r\n					<div class=\"col-md-6 index_about_main_left\">\r\n						<p>\r\n							河南大岸信息技术有限公司，创建于2012年，专注于企事业单位设备资产管理方面存在的问题， 提供企业设备资产全生命周期管理解决方案和设备维护管理系统的实施服务。我们的自主产品DA-EAM系统， 是参考资深行业专家的设计理念和我们多年设备资产管理系统现场实施经验，总结开发的一套设备资产全生命周期 管理系统，拥有多项著作权证书，完全自主产权。适合企事业单位和工厂使用，可以获得量化的收益，还可以自由选择 部署在云服务器或本地服务器。另外，我们拥有稳定的技术开发团队，成熟的实施服务体系，可以提供软硬一体的产品定制开发， 移动应用APP、微信公众号、微信小程序的开发和后产品的运维服务......\r\n\r\n						</p>\r\n						<div>\r\n							<a href=\"#\" class=\"btn btn-small btn-primary\">查看更多>></a>\r\n						</div>\r\n					</div>\r\n					<div class=\"col-md-6 index_about_main_right\">\r\n						<span>\r\n							<img src=\"fh_static_1/images/feature2.jpg\" />\r\n						</span>\r\n					</div>\r\n				</div>\r\n			</div>\r\n		</div>\r\n\r\n		<!--产品中心-->\r\n\r\n		<div class=\"pro_wrap container-fluid padding60\">\r\n\r\n			<div class=\"h2 index_title text-center\">\r\n				产品中心\r\n				<span class=\"line\"></span>\r\n				<p>专注于解决企事业单位设备资产管理方面存在的问题</p>\r\n			</div>\r\n\r\n			<div class=\"container padding_top30\">\r\n				<div class=\"row\">\r\n					<div class=\"col-md-3 pro_box\">\r\n						<a href=\"#\">\r\n							<div class=\"pro_img_box\">\r\n								<img src=\"fh_static_1/images/1.jpg\" />\r\n							</div>\r\n							<p>产品名称</p>\r\n						</a>\r\n					</div>\r\n\r\n					<div class=\"col-md-3 pro_box\">\r\n						<a href=\"#\">\r\n							<div class=\"pro_img_box\">\r\n								<img src=\"fh_static_1/images/1.jpg\" />\r\n							</div>\r\n							<p>产品名称</p>\r\n						</a>\r\n					</div>\r\n\r\n					<div class=\"col-md-3 pro_box\">\r\n						<a href=\"#\">\r\n							<div class=\"pro_img_box\">\r\n								<img src=\"fh_static_1/images/1.jpg\" />\r\n							</div>\r\n							<p>产品名称</p>\r\n						</a>\r\n					</div>\r\n\r\n					<div class=\"col-md-3 pro_box\">\r\n						<a href=\"#\">\r\n							<div class=\"pro_img_box\">\r\n								<img src=\"fh_static_1/images/1.jpg\" />\r\n							</div>\r\n							<p>产品名称</p>\r\n						</a>\r\n					</div>\r\n\r\n				</div>\r\n			</div>\r\n\r\n			<div class=\"text-center\">\r\n				<a class=\"btn btn-large btn-primary\">查看更多>></a>\r\n			</div>\r\n\r\n		</div>\r\n\r\n		<!--首页新闻中心-->\r\n		<div class=\"container-fluid news_wrap padding60\">\r\n			<div class=\"h2 index_title text-center\">\r\n				行业新闻\r\n				<span class=\"line\"></span>\r\n				<p>专注于解决企事业单位设备资产管理方面存在的问题</p>\r\n			</div>\r\n\r\n			<div class=\"container padding_top30\">\r\n				<div class=\"row\">\r\n					<div class=\"col-md-6 index_news_left\">\r\n						<span>\r\n							<img src=\"fh_static_1/images/feature2.jpg\" />\r\n						</span>\r\n					</div>\r\n					<div class=\"col-md-6 index_news_right\">\r\n						<ul>\r\n							<li>\r\n								<a href=\"#\">\r\n									<span>\r\n										<p class=\"date_year\">2018-5</p>\r\n										<p class=\"date_day\">27</p>\r\n									</span>\r\n									<div>\r\n										<h4>这是条很长很长的新闻标题这是条很长很长的新闻标题这是条很长很长的新闻标题</h4>\r\n										<p>2018年是协同市场发展面临新机遇的一年，面对云计算、大数据、人工智能等新兴技术的推动， 中国的经济发展走向数字化转型，在此趋势下，中国的企事业组织纷纷进行数字化转型探索，作 为连接人与组织的高绩效运营平台，协同管理平台也随之越来越被关注和重视，成为组织信息化的基础设施\r\n										</p>\r\n									</div>\r\n								</a>\r\n							</li>\r\n							<li>\r\n								<a href=\"#\">\r\n									<span>\r\n										<p class=\"date_year\">2018-5</p>\r\n										<p class=\"date_day\">27</p>\r\n									</span>\r\n									<div>\r\n										<h4>这是条很长很长的新闻标题这是条很长很长的新闻标题这是条很长很长的新闻标题</h4>\r\n										<p>2018年是协同市场发展面临新机遇的一年，面对云计算、大数据、人工智能等新兴技术的推动， 中国的经济发展走向数字化转型，在此趋势下，中国的企事业组织纷纷进行数字化转型探索，作 为连接人与组织的高绩效运营平台，协同管理平台也随之越来越被关注和重视，成为组织信息化的基础设施\r\n										</p>\r\n									</div>\r\n								</a>\r\n							</li>\r\n							<li>\r\n								<a href=\"#\">\r\n									<span>\r\n										<p class=\"date_year\">2018-5</p>\r\n										<p class=\"date_day\">27</p>\r\n									</span>\r\n									<div>\r\n										<h4>这是条很长很长的新闻标题这是条很长很长的新闻标题这是条很长很长的新闻标题</h4>\r\n										<p>2018年是协同市场发展面临新机遇的一年，面对云计算、大数据、人工智能等新兴技术的推动， 中国的经济发展走向数字化转型，在此趋势下，中国的企事业组织纷纷进行数字化转型探索，作 为连接人与组织的高绩效运营平台，协同管理平台也随之越来越被关注和重视，成为组织信息化的基础设施\r\n										</p>\r\n									</div>\r\n								</a>\r\n							</li>\r\n						</ul>\r\n					</div>\r\n				</div>\r\n			</div>\r\n\r\n			<div class=\"text-center padding_top30\">\r\n				<a class=\"btn btn-large btn-primary\">查看更多>></a>\r\n			</div>\r\n\r\n		</div>\r\n\r\n		<!--售后服务-->\r\n		<div class=\"container-fluid service_wrap padding60\">\r\n			<div class=\"h2 index_title text-center\">\r\n				售后服务\r\n				<span class=\"line\"></span>\r\n				<p>专注于解决企事业单位设备资产管理方面存在的问题</p>\r\n			</div>\r\n\r\n			<div class=\"container\">\r\n				<div class=\"index_service_main clearfix padding_top30 row\">\r\n\r\n					<div class=\" index_service_main_box col-md-3\">\r\n						<div class=\"service_main_box_img text-center\">\r\n							<span>\r\n				       		<img   src=\"fh_static_1/images/s1.png\">   \r\n				        </span>\r\n						</div>\r\n						<p class=\"service_main_box_title text-center\">检查维护</p>\r\n						<div class=\"service_main_box_line\">\r\n							<span></span>\r\n						</div>\r\n						<div class=\"service_main_box_summary text-center\">\r\n							定期检查和维护应按照建筑的要求对中压配电盘进行定期检查和维护\r\n						</div>\r\n					</div>\r\n\r\n					<div class=\" index_service_main_box col-md-3\">\r\n						<div class=\"service_main_box_img text-center\">\r\n							<span>\r\n				       		<img   src=\"fh_static_1/images/s2.png\">   \r\n				        </span>\r\n						</div>\r\n						<p class=\"service_main_box_title text-center\">电话咨询</p>\r\n						<div class=\"service_main_box_line\">\r\n							<span></span>\r\n						</div>\r\n						<div class=\"service_main_box_summary text-center\">\r\n							热线以方便、快捷、保密等特点提供服务，咨询服务的一种扩展和延伸。\r\n						</div>\r\n					</div>\r\n\r\n					<div class=\" index_service_main_box col-md-3\">\r\n						<div class=\"service_main_box_img text-center\">\r\n							<span>\r\n				       		<img   src=\"fh_static_1/images/s3.png\">   \r\n				        </span>\r\n						</div>\r\n						<p class=\"service_main_box_title text-center\">长时在线</p>\r\n						<div class=\"service_main_box_line\">\r\n							<span></span>\r\n						</div>\r\n						<div class=\"service_main_box_summary text-center\">\r\n							拥有普通话、英语座席，24小时客户服务热线。\r\n						</div>\r\n					</div>\r\n\r\n					<div class=\" index_service_main_box col-md-3\">\r\n						<div class=\"service_main_box_img text-center\">\r\n							<span>\r\n				       		<img   src=\"fh_static_1/images/s4.png\">   \r\n				        </span>\r\n						</div>\r\n						<p class=\"service_main_box_title text-center\">诚信合作</p>\r\n						<div class=\"service_main_box_line\">\r\n							<span></span>\r\n						</div>\r\n						<div class=\"service_main_box_summary text-center\">\r\n							遵循诚信、公平、互利的合作原则，是合作共赢的根本保证。\r\n						</div>\r\n					</div>\r\n\r\n				</div>\r\n\r\n			</div>\r\n\r\n		</div>\r\n\r\n		<!--友情链接-->\r\n\r\n		<div class=\"friendLink_wrap container-fluid padding60\">\r\n			<div class=\"h2 index_title text-center\">\r\n				合作客户\r\n				<span class=\"line\"></span>\r\n				<p>更多客户的不二选择</p>\r\n			</div>\r\n			<div class=\"row padding_top30\">\r\n				<ul class=\"clearfix\">\r\n					<li class=\"col-md-2\">\r\n						<a>\r\n							<img src=\"fh_static_1/images/l1.jpg\" />\r\n						</a>\r\n					</li>\r\n					<li class=\"col-md-2\">\r\n						<a>\r\n							<img src=\"fh_static_1/images/l2.jpg\" />\r\n						</a>\r\n					</li>\r\n					<li class=\"col-md-2\">\r\n						<a>\r\n							<img src=\"fh_static_1/images/l3.jpg\" />\r\n						</a>\r\n					</li>\r\n					<li class=\"col-md-2\">\r\n						<a>\r\n							<img src=\"fh_static_1/images/l4.jpg\" />\r\n						</a>\r\n					</li>\r\n					<li class=\"col-md-2\">\r\n						<a>\r\n							<img src=\"fh_static_1/images/l5.jpg\" />\r\n						</a>\r\n					</li>\r\n					<li class=\"col-md-2\">\r\n						<a>\r\n							<img src=\"fh_static_1/images/l6.jpg\" />\r\n						</a>\r\n					</li>\r\n					<li class=\"col-md-2\">\r\n						<a>\r\n							<img src=\"fh_static_1/images/l1.jpg\" />\r\n						</a>\r\n					</li>\r\n					<li class=\"col-md-2\">\r\n						<a>\r\n							<img src=\"fh_static_1/images/l2.jpg\" />\r\n						</a>\r\n					</li>\r\n					<li class=\"col-md-2\">\r\n						<a>\r\n							<img src=\"fh_static_1/images/l3.jpg\" />\r\n						</a>\r\n					</li>\r\n					<li class=\"col-md-2\">\r\n						<a>\r\n							<img src=\"fh_static_1/images/l4.jpg\" />\r\n						</a>\r\n					</li>\r\n					<li class=\"col-md-2\">\r\n						<a>\r\n							<img src=\"fh_static_1/images/l5.jpg\" />\r\n						</a>\r\n					</li>\r\n					<li class=\"col-md-2\">\r\n						<a>\r\n							<img src=\"fh_static_1/images/l6.jpg\" />\r\n						</a>\r\n					</li>\r\n				</ul>\r\n			</div>\r\n\r\n		</div>\r\n\r\n		<!--底部-->\r\n		<div class=\"foot text-center\">\r\n			<strong>\r\n			    <a href=\"http://www.miibeian.gov.cn\" target=\"_blank\" rel=\"nofollow\">\r\n			      <span>B2-20090055-1 </span>\r\n			    </a> | \r\n			    <a href=\"/index.html\">\r\n			      <span>河南大岸信息技术有限公司</span>\r\n			    </a>\r\n		    \r\n		    </strong>\r\n			<br> 通讯地址：\r\n			<span>郑州市高新区升龙有一城B座23楼635室</span> &nbsp;&nbsp;&nbsp;&nbsp;联系人：\r\n			<span>段菲</span> &nbsp;&nbsp;&nbsp;&