INSERT INTO `web_aboutus` VALUES ('1', '<p style=\"padding: 0px 0px 1em; color: rgb(90, 90, 90); line-height: 27px; text-indent: 32px; font-family: 宋体; font-size: 12px; margin-top: 0px; margin-bottom: 0px; white-space: normal; background-color: rgb(255, 255, 255);\"><span style=\"font-family: 宋体; font-size: 19px;\">&nbsp;河南大岸信息技术有限公司创建于</span><span style=\"font-family: Calibri; font-size: 19px;\">2012</span><span style=\"font-family: 宋体; font-size: 19px;\">年，专注于企事业单位设备资产管理问题，提供企业设备资产全生命周期管理解决方案和设备维护管理系统实施服务。我们的自由产品</span><span style=\"font-family: Calibri; font-size: 19px;\">DA-EAM</span><span style=\"font-family: 宋体; font-size: 19px;\">系统，是专门由资深行业专家设计和开发的设备资产全生命周期管理系统，拥有多项著作权证书，完全自主产权。适合企事业单位和工厂使用并可以获得量化的收益，云端部署和本地部署皆可。</span></p><p style=\"padding: 0px 0px 1em; color: rgb(90, 90, 90); line-height: 27px; text-indent: 32px; font-family: 宋体; font-size: 12px; margin-top: 0px; margin-bottom: 0px; white-space: normal; background-color: rgb(255, 255, 255);\"><span style=\"font-family: 宋体; font-size: 19px;\"><strong>文化与愿景</strong></span></p><p style=\"padding: 0px 0px 1em; color: rgb(90, 90, 90); line-height: 27px; text-indent: 32px; font-family: 宋体; font-size: 12px; margin-top: 0px; margin-bottom: 0px; white-space: normal; background-color: rgb(255, 255, 255);\"><span style=\"font-family: 宋体; font-size: 19px;\">文化：诚信、务实、创新、共赢</span></p><p style=\"padding: 0px 0px 1em; color: rgb(90, 90, 90); line-height: 27px; text-indent: 32px; font-family: 宋体; font-size: 12px; margin-top: 0px; margin-bottom: 0px; white-space: normal; background-color: rgb(255, 255, 255);\"><span style=\"font-family: 宋体; font-size: 19px;\">愿景：致力于打造中国最好</span></p><p style=\"padding: 0px 0px 1em; color: rgb(90, 90, 90); line-height: 27px; text-indent: 32px; font-family: 宋体; font-size: 12px; margin-top: 0px; margin-bottom: 0px; white-space: normal; background-color: rgb(255, 255, 255);\"><span style=\"font-family: 宋体; font-size: 19px;\"><strong>商务与服务</strong></span></p><p style=\"padding: 0px 0px 1em; color: rgb(90, 90, 90); line-height: 27px; text-indent: 32px; font-family: 宋体; font-size: 12px; margin-top: 0px; margin-bottom: 0px; white-space: normal; background-color: rgb(255, 255, 255);\"><span style=\"font-family: 宋体; font-size: 19px;\">诚信、守信、不予言败是我们发展的宗旨，与客户交流遵循的原则；创新变革，创造奇迹是我们坚定的方向；客户至上，技术为本是我们服务的态度。</span></p><p style=\"padding: 0px 0px 1em; color: rgb(90, 90, 90); line-height: 27px; text-indent: 32px; font-family: 宋体; font-size: 12px; margin-top: 0px; margin-bottom: 0px; white-space: normal; background-color: rgb(255, 255, 255);\"><span style=\"font-family: 宋体; font-size: 19px;\"><strong>责任与创新</strong></span></p><p style=\"padding: 0px 0px 1em; color: rgb(90, 90, 90); line-height: 27px; text-indent: 32px; font-family: 宋体; font-size: 12px; margin-top: 0px; margin-bottom: 0px; white-space: normal; background-color: rgb(255, 255, 255);\"><span style=\"font-family: 宋体; font-size: 19px;\">现如今，世界已经进入智能社会，其广度和深度难以想象。这大机会时代，给千百万家企业提供了千载难逢的机会，中国企业一定要有与时俱进不断创新的战略思维与实际行动。恰如习近平总书记指出的：“不创新不行，创新慢了也不行。如果我们不识变、不求变，就可能陷入战略被动，错失发展机遇，甚至错过整整一个时代”。</span></p><p style=\"padding: 0px 0px 1em; color: rgb(90, 90, 90); line-height: 27px; text-indent: 32px; font-family: 宋体; font-size: 12px; margin-top: 0px; margin-bottom: 0px; white-space: normal; background-color: rgb(255, 255, 255);\"><span style=\"line-height: 26.66px; font-size: 12px;\"></span></p><p>&nbsp;</p>');
INSERT INTO `web_contactus` VALUES ('1', '<p>公司电话： 0371-61318009</p><p>手机号码： 13253310008</p><p>公司邮箱： hnda2008@163.com&nbsp;</p><p>公司网址： www.daaninfo.com</p><p>公司地址： 郑州市高新区科学大道与长椿路交叉口升龙又一城B座</p><p><br/></p>', '34.812386', '113.550553', '15');
INSERT INTO `web_cooperation` VALUES ('1', '<p style=\"padding: 0px; color: rgb(102, 102, 102); line-height: 24px; text-indent: 2em; font-family: &quot;Microsoft Yahei&quot;, arial, Tahoma, sans-serif; font-size: 14px; margin-top: 0px; margin-bottom: 0px; white-space: normal; background-repeat: no-repeat; background-color: rgb(252, 252, 252);\"><span style=\"color: rgb(0, 0, 0); font-family: 宋体; background-repeat: no-repeat;\">&nbsp;&nbsp;&nbsp;为了快速响应客户各种个性化需求，我们提供弹性的ODM/OEM合作模式，可为客户提供设计文件、软件映像文件、软件源代码、相关文档及PCB、PCBA、整机等。</span></p><p style=\"padding: 0px; color: rgb(102, 102, 102); line-height: 24px; text-indent: 2em; font-family: &quot;Microsoft Yahei&quot;, arial, Tahoma, sans-serif; font-size: 14px; margin-top: 0px; margin-bottom: 0px; white-space: normal; background-repeat: no-repeat; background-color: rgb(252, 252, 252);\"><span style=\"color: rgb(0, 0, 0); background-repeat: no-repeat;\">&nbsp;</span></p><p style=\"padding: 0px; color: rgb(102, 102, 102); line-height: 24px; text-indent: 2em; font-family: &quot;Microsoft Yahei&quot;, arial, Tahoma, sans-serif; font-size: 14px; margin-top: 0px; margin-bottom: 0px; white-space: normal; background-repeat: no-repeat; background-color: rgb(252, 252, 252);\"><strong style=\"background-repeat: no-repeat;\"><span style=\"color: rgb(0, 0, 0); font-family: 宋体; background-repeat: no-repeat;\">主要合作方式:</span></strong></p><p style=\"padding: 0px; color: rgb(102, 102, 102); line-height: 24px; text-indent: 2em; font-family: &quot;Microsoft Yahei&quot;, arial, Tahoma, sans-serif; font-size: 14px; margin-top: 0px; margin-bottom: 0px; white-space: normal; background-repeat: no-repeat; background-color: rgb(252, 252, 252);\"><span style=\"color: rgb(0, 0, 0); background-repeat: no-repeat;\">&nbsp;</span></p><p style=\"padding: 0px; color: rgb(102, 102, 102); line-height: 24px; text-indent: 2em; font-family: &quot;Microsoft Yahei&quot;, arial, Tahoma, sans-serif; font-size: 14px; margin-top: 0px; margin-bottom: 0px; white-space: normal; background-repeat: no-repeat; background-color: rgb(252, 252, 252);\"><strong style=\"background-repeat: no-repeat;\"><span style=\"color: rgb(0, 0, 0); font-family: 宋体; background-repeat: no-repeat;\">&nbsp;1</span><span style=\"color: rgb(0, 0, 0); font-family: 宋体; background-repeat: no-repeat;\">、完全研发项目：</span></strong><span style=\"color: rgb(0, 0, 0); font-family: 宋体; background-repeat: no-repeat;\">根据客户产品方案书或具体功能要求，选择CPU平台，进行软（系统级别）、硬件开发，制作样机，或针对客户原有产品进行软、硬件升级，样机制作，同时您还将得到专业的、技术人员培训、辅导服务以及终身技术维护，我们提供所有产品资料。</span></p><p style=\"padding: 0px; color: rgb(102, 102, 102); line-height: 24px; text-indent: 2em; font-family: &quot;Microsoft Yahei&quot;, arial, Tahoma, sans-serif; font-size: 14px; margin-top: 0px; margin-bottom: 0px; white-space: normal; background-repeat: no-repeat; background-color: rgb(252, 252, 252);\"><span style=\"color: rgb(0, 0, 0); background-repeat: no-repeat;\">&nbsp;</span></p><p style=\"padding: 0px; color: rgb(102, 102, 102); line-height: 24px; text-indent: 2em; font-family: &quot;Microsoft Yahei&quot;, arial, Tahoma, sans-serif; font-size: 14px; margin-top: 0px; margin-bottom: 0px; white-space: normal; background-repeat: no-repeat; background-color: rgb(252, 252, 252);\"><span style=\"color: rgb(0, 0, 0); font-family: 宋体; background-repeat: no-repeat;\">&nbsp;</span><strong style=\"background-repeat: no-repeat;\"><span style=\"color: rgb(0, 0, 0); font-family: 宋体; background-repeat: no-repeat;\">2</span><span style=\"color: rgb(0, 0, 0); font-family: 宋体; background-repeat: no-repeat;\">、研发及生产项目：</span></strong><span style=\"color: rgb(0, 0, 0); font-family: 宋体; background-repeat: no-repeat;\">根据客户需求，定制研发客户规格产品，样机确认后批量生产，以最终整机交付客户。</span></p><p style=\"padding: 0px; color: rgb(102, 102, 102); line-height: 24px; text-indent: 2em; font-family: &quot;Microsoft Yahei&quot;, arial, Tahoma, sans-serif; font-size: 14px; margin-top: 0px; margin-bottom: 0px; white-space: normal; background-repeat: no-repeat; background-color: rgb(252, 252, 252);\"><span style=\"color: rgb(0, 0, 0); background-repeat: no-repeat;\">&nbsp;</span></p><p style=\"padding: 0px; color: rgb(102, 102, 102); line-height: 24px; text-indent: 2em; font-family: &quot;Microsoft Yahei&quot;, arial, Tahoma, sans-serif; font-size: 14px; margin-top: 0px; margin-bottom: 0px; white-space: normal; background-repeat: no-repeat; background-color: rgb(252, 252, 252);\"><strong style=\"background-repeat: no-repeat;\"><span style=\"color: rgb(0, 0, 0); font-family: 宋体; background-repeat: no-repeat;\">&nbsp;3</span><span style=\"color: rgb(0, 0, 0); font-family: 宋体; background-repeat: no-repeat;\">．标准产品销售：</span></strong><span style=\"color: rgb(0, 0, 0); font-family: 宋体; background-repeat: no-repeat;\">客户可以选购我们一系列的标准产品，直接下单采购，不需额外付任何研发费及模具费。</span></p><p style=\"padding: 0px; text-align: center; color: rgb(102, 102, 102); line-height: 21px; text-indent: 2em; font-family: &quot;Microsoft Yahei&quot;, arial, Tahoma, sans-serif; font-size: 14px; margin-top: 0px; margin-bottom: 0px; white-space: normal; background-repeat: no-repeat; background-color: rgb(252, 252, 252);\"><span style=\"font-family: 宋体; background-repeat: no-repeat;\"><br style=\"background-repeat: no-repeat;\"/></span></p><p style=\"padding: 0px; text-align: center; color: rgb(102, 102, 102); line-height: 21px; text-indent: 2em; font-family: &quot;Microsoft Yahei&quot;, arial, Tahoma, sans-serif; font-size: 14px; margin-top: 0px; margin-bottom: 0px; white-space: normal; background-repeat: no-repeat; background-color: rgb(252, 252, 252);\"><span style=\"font-family: 宋体; background-repeat: no-repeat;\"><img width=\"650\" height=\"236\" title=\"clip_image002.png\" style=\"border: currentColor; border-image: none; width: 650px; height: 236px; background-repeat: no-repeat;\" src=\"http://info.emdoor.com/ueditor1.2.5/asp/upload/2014092858921669.png\" border=\"0\" hspace=\"0\"/></span></p><p style=\"padding: 0px; text-align: center; color: rgb(102, 102, 102); line-height: 21px; text-indent: 2em; font-family: &quot;Microsoft Yahei&quot;, arial, Tahoma, sans-serif; font-size: 14px; margin-top: 0px; margin-bottom: 0px; white-space: normal; background-repeat: no-repeat; background-color: rgb(252, 252, 252);\"><span style=\"font-family: 宋体; background-repeat: no-repeat;\"><br style=\"background-repeat: no-repeat;\"/></span></p><p style=\"padding: 0px; color: rgb(102, 102, 102); line-height: 21px; text-indent: 32px; font-family: &quot;Microsoft Yahei&quot;, arial, Tahoma, sans-serif; font-size: 14px; margin-top: 0px; margin-bottom: 0px; white-space: normal; background-repeat: no-repeat; background-color: rgb(252, 252, 252);\"><span style=\"color: rgb(0, 0, 0); font-family: 宋体; background-repeat: no-repeat;\">针对ODM方式，我们可以提供完整系统（包括硬件PCBA和操作系统及驱动程序），也可提供部分保证客户二次开发所必需的文件、线路图纸等，供客户灵活选择，以期让客户以最低廉的成本获得最具性价比的方案。</span></p><p><span style=\"color: rgb(0, 0, 0); font-family: 宋体; background-repeat: no-repeat;\"><br/></span></p><p><br/></p>');
