INSERT INTO `web_news` VALUES ('0884e2245bdf4c5b9346cc41588954c7', 'd0f364be931a45a9929dd98439cb20bc', '新华社北京7月31日电', '2018-08-01 12:57:00', '新华社北京7月31日电', 'http://222.137.19.253:8086/dashop/uploadFiles/uploadImgs/20180801/d9d898ca48ef4c9abb946ea630eeee7c.jpg', '新华社北京7月31日电? 7月17日，中共中央在中南海召开党外人士座谈会，就当前经济形势和下半年经济工作听取各民主党派中央', '<p style=\"font: 400 18px/32px &quot;Microsoft Yahei&quot;; margin: 32px 0px 0px; padding: 0px; text-align: justify; color: rgb(64, 64, 64); text-transform: none; text-indent: 2em; letter-spacing: normal; word-spacing: 0px; white-space: normal; orphans: 2; widows: 2; font-size-adjust: none; font-stretch: normal; background-color: rgb(255, 255, 255); -webkit-text-stroke-width: 0px; text-decoration-style: initial; text-decoration-color: initial;\">新华社北京7月31日电? 7月17日，中共中央在中南海召开党外人士座谈会，就当前经济形势和下半年经济工作听取各民主党派中央、全国工商联负责人和无党派人士代表的意见建议。中共中央总书记习近平主持座谈会并发表重要讲话。他强调，要发挥中国共产党领导的多党合作和政治协商制度的优势，当好中国共产党的好参谋、好帮手、好同事，促进科学决策、民主决策、依法决策，推进国家治理体系和治理能力现代化，共同把中国的事情办好。</p><p style=\"font: 400 18px/32px &quot;Microsoft Yahei&quot;; margin: 32px 0px 0px; padding: 0px; text-align: justify; color: rgb(64, 64, 64); text-transform: none; text-indent: 2em; letter-spacing: normal; word-spacing: 0px; white-space: normal; orphans: 2; widows: 2; font-size-adjust: none; font-stretch: normal; background-color: rgb(255, 255, 255); -webkit-text-stroke-width: 0px; text-decoration-style: initial; text-decoration-color: initial;\">中共中央政治局常委李克强、汪洋、王沪宁、韩正出席座谈会。李克强通报了上半年经济工作有关情况，介绍了中共中央关于做好下半年经济工作的考虑。</p><p style=\"font: 400 18px/32px &quot;Microsoft Yahei&quot;; margin: 32px 0px 0px; padding: 0px; text-align: justify; color: rgb(64, 64, 64); text-transform: none; text-indent: 2em; letter-spacing: normal; word-spacing: 0px; white-space: normal; orphans: 2; widows: 2; font-size-adjust: none; font-stretch: normal; background-color: rgb(255, 255, 255); -webkit-text-stroke-width: 0px; text-decoration-style: initial; text-decoration-color: initial;\">座谈会上，民革中央主席万鄂湘、民盟中央主席丁仲礼、民建中央主席郝明金、民进中央主席蔡达峰、农工党中央主席陈竺、致公党中央主席万钢、九三学社中央主席武维华、台盟中央主席苏辉、全国工商联主席高云龙、无党派人士代表林毅夫先后发言。他们赞同中共中央对当前我国经济形势的分析和下半年经济工作的考虑，并就推进供给侧结构性改革、实施健康中国战略、建设粤港澳大湾区、优化营商环境、增强经济平稳健康发展动力、加强青藏高原生态文明建设、做好重点区域农业面源污染治理、深化两岸民间产业合作等提出意见和建议。</p><p style=\"font: 400 18px/32px &quot;Microsoft Yahei&quot;; margin: 32px 0px 0px; padding: 0px; text-align: justify; color: rgb(64, 64, 64); text-transform: none; text-indent: 2em; letter-spacing: normal; word-spacing: 0px; white-space: normal; orphans: 2; widows: 2; font-size-adjust: none; font-stretch: normal; background-color: rgb(255, 255, 255); -webkit-text-stroke-width: 0px; text-decoration-style: initial; text-decoration-color: initial;\">在认真听取大家发言后，习近平总书记作了重要讲话。他表示，今年以来，面对国内外形势的深刻复杂变化，中共中央观大势、把方向、谋全局，各地区各部门按照中共中央部署，坚持稳中求进工作总基调，坚持新发展理念，落实高质量发展的要求，推进供给侧结构性改革，加快改革开放步伐，着力打好“三大攻坚战”，我国经济发展取得了新成绩。</p><p style=\"font: 400 18px/32px &quot;Microsoft Yahei&quot;; margin: 32px 0px 0px; padding: 0px; text-align: justify; color: rgb(64, 64, 64); text-transform: none; text-indent: 2em; letter-spacing: normal; word-spacing: 0px; white-space: normal; orphans: 2; widows: 2; font-size-adjust: none; font-stretch: normal; background-color: rgb(255, 255, 255); -webkit-text-stroke-width: 0px; text-decoration-style: initial; text-decoration-color: initial;\">习近平强调，各民主党派中央、全国工商联和无党派人士牢牢把握稳增长、促改革、调结构、惠民生、防风险的部署要求，聚焦推动高质量发展、实施乡村振兴战略、实施区域协调发展战略等重大问题，深入一线考察调研，提出意见和建议，为中共中央科学决策、有效施策提供了重要依据。特别是各民主党派中央主要负责同志坚持问题导向，亲赴扶贫一线蹲点调研，掌握第一手资料，听取第一线声音，深入开展脱贫攻坚民主监督，为打赢脱贫攻坚战作出了积极贡献，展示了新气象、新面貌、新作为。习近平代表中共中央向同志们表示衷心的感谢。</p><p style=\"font: 400 18px/32px &quot;Microsoft Yahei&quot;; margin: 32px 0px 0px; padding: 0px; text-align: justify; color: rgb(64, 64, 64); text-transform: none; text-indent: 2em; letter-spacing: normal; word-spacing: 0px; white-space: normal; orphans: 2; widows: 2; font-size-adjust: none; font-stretch: normal; background-color: rgb(255, 255, 255); -webkit-text-stroke-width: 0px; text-decoration-style: initial; text-decoration-color: initial;\">习近平指出，大家在发言中充分肯定了上半年经济工作取得的成绩，并就正确认识当前经济形势、做好下半年经济工作提出了针对性很强的意见，我们将认真研究、积极吸纳。</p><p style=\"font: 400 18px/32px &quot;Microsoft Yahei&quot;; margin: 32px 0px 0px; padding: 0px; text-align: justify; color: rgb(64, 64, 64); text-transform: none; text-indent: 2em; letter-spacing: normal; word-spacing: 0px; white-space: normal; orphans: 2; widows: 2; font-size-adjust: none; font-stretch: normal; background-color: rgb(255, 255, 255); -webkit-text-stroke-width: 0px; text-decoration-style: initial; text-decoration-color: initial;\">习近平强调，下半年，我们要坚持稳中求进工作总基调，在保持经济社会大局稳定的基础上，在改革开放和结构调整等方面积极进取，加强统筹协调，形成政策合力，扎实细致工作，稳就业、稳金融、稳外贸、稳外资、稳投资、稳预期，做好民生保障和社会稳定工作，统筹做好经济社会发展工作，保持经济平稳健康发展。</p><p style=\"font: 400 18px/32px &quot;Microsoft Yahei&quot;; margin: 32px 0px 0px; padding: 0px; text-align: justify; color: rgb(64, 64, 64); text-transform: none; text-indent: 2em; letter-spacing: normal; word-spacing: 0px; white-space: normal; orphans: 2; widows: 2; font-size-adjust: none; font-stretch: normal; background-color: rgb(255, 255, 255); -webkit-text-stroke-width: 0px; text-decoration-style: initial; text-decoration-color: initial;\">习近平给大家提出3点希望。一是希望大家正确认识当前经济形势，保持信心、坚定决心，更广泛地凝聚共识。要把思想和行动统一到中共中央关于当前经济形势的分析和判断上来，深入学习贯彻中共十九大精神，更加紧密地团结在中共中央周围，坚定不移把中国特色社会主义伟大事业推向前进。二是希望大家聚焦中共十九大确定的目标任务，发挥特点优势，为推动高质量发展献计出力。要聚焦中共十九大作出的重大决策部署，紧扣我国社会主要矛盾变化，围绕实施重大战略，围绕打赢“三大攻坚战”等经济社会发展重大问题、全面深化改革难点问题、推动创新创造关键问题、事关人民群众切身利益问题，深入考察调研，多深入基层寻计问策，提出更多有价值、有分量的意见和建议。三是希望大家正确认识当前社会热点问题，加强思想引导，为经济社会发展营造良好环境。要密切关注广大成员和所联系群众的思想动态，加强沟通和引导，使他们客观看待当前形势，相信有中共中央坚强领导和全国人民共同努力，有改革开放40年发展积累的坚实基础、丰富经验，有广阔的国内市场、经济发展的韧性、潜力和回旋余地，我们有能力战胜各种风险挑战。要开展深入细致的思想工作，引导广大成员和所联系群众理解改革、投身改革、支持改革、参与改革，努力维护社会和谐稳定。</p><p style=\"font: 400 18px/32px &quot;Microsoft Yahei&quot;; margin: 32px 0px 0px; padding: 0px; text-align: justify; color: rgb(64, 64, 64); text-transform: none; text-indent: 2em; letter-spacing: normal; word-spacing: 0px; white-space: normal; orphans: 2; widows: 2; font-size-adjust: none; font-stretch: normal; background-color: rgb(255, 255, 255); -webkit-text-stroke-width: 0px; text-decoration-style: initial; text-decoration-color: initial;\">丁薛祥、刘鹤、胡春华、尤权、王勇、肖捷、何立峰，中共中央、国务院有关部门负责人出席座谈会。</p><p style=\"font: 400 18px/32px &quot;Microsoft Yahei&quot;; margin: 32px 0px 0px; padding: 0px; text-align: justify; color: rgb(64, 64, 64); text-transform: none; text-indent: 2em; letter-spacing: normal; word-spacing: 0px; white-space: normal; orphans: 2; widows: 2; font-size-adjust: none; font-stretch: normal; background-color: rgb(255, 255, 255); -webkit-text-stroke-width: 0px; text-decoration-style: initial; text-decoration-color: initial;\">出席座谈会的党外人士还有陈晓光、郑建邦、辜胜阻、刘新成、何维、邵鸿和蒋作君、李钺锋、张伯军、张道宏、李世杰、朱永新、曹鸿鸣、赖明、黄荣、高鸿钧等。</p><p></p>', '0', '1', '1', '7a0586b8753540e6b686e31142f571ee', '1', '1', 'app', null);
INSERT INTO `web_news` VALUES ('1102aa472595489f81162868518f0bba', '50b79e1fc9654c0282792e8fa9f78ed0', '​今天家居妹给大家带来一', '2018-08-01 12:57:50', '​今天家居妹给大家带来一', 'http://222.137.19.253:8086/dashop/uploadFiles/uploadImgs/20180801/c62d7d77b69c408487294cba0dcf8d22.jpg', '今天家居妹给大家带来一个设计上很精彩的60㎡小两居案例。虽然只是个面积偏小的两居室，却是小户型中的战斗机，一家六口生活在一起毫不拥挤。', '<p style=\"font: 400 18px/32px &quot;Microsoft Yahei&quot;; margin: 32px 0px 0px; padding: 0px; text-align: justify; color: rgb(64, 64, 64); text-transform: none; text-indent: 2em; letter-spacing: normal; word-spacing: 0px; white-space: normal; orphans: 2; widows: 2; font-size-adjust: none; font-stretch: normal; background-color: rgb(255, 255, 255); -webkit-text-stroke-width: 0px; text-decoration-style: initial; text-decoration-color: initial;\">今天家居妹给大家带来一个设计上很精彩的60㎡小两居案例。虽然只是个面积偏小的两居室，却是小户型中的战斗机，一家六口生活在一起毫不拥挤。</p><p class=\"f_center\" style=\"font: 400 18px/32px &quot;Microsoft Yahei&quot;; margin: 32px 0px 0px; padding: 0px; text-align: center; color: rgb(64, 64, 64); text-transform: none; text-indent: 0px; letter-spacing: normal; word-spacing: 0px; white-space: normal; orphans: 2; widows: 2; font-size-adjust: none; font-stretch: normal; background-color: rgb(255, 255, 255); -webkit-text-stroke-width: 0px; text-decoration-style: initial; text-decoration-color: initial;\"><img style=\"border: 0px currentColor; border-image: none; vertical-align: top;\" alt=\"60㎡老房仅花27天变高科技住宅，6人生活毫不拥挤\" src=\"http://cms-bucket.nosdn.127.net/2018/07/31/eac63dec05f94070a6246912c0b4fe9c.jpeg?imageView&thumbnail=550x0\"/><br/></p><p style=\"font: 400 18px/32px &quot;Microsoft Yahei&quot;; margin: 32px 0px 0px; padding: 0px; text-align: justify; color: rgb(64, 64, 64); text-transform: none; text-indent: 2em; letter-spacing: normal; word-spacing: 0px; white-space: normal; orphans: 2; widows: 2; font-size-adjust: none; font-stretch: normal; background-color: rgb(255, 255, 255); -webkit-text-stroke-width: 0px; text-decoration-style: initial; text-decoration-color: initial;\">可别看改造后的房子干净整洁，它改造前的模样实在乱糟糟，可以说是老房装修的典型例子。</p><p class=\"f_center\" style=\"font: 400 18px/32px &quot;Microsoft Yahei&quot;; margin: 32px 0px 0px; padding: 0px; text-align: center; color: rgb(64, 64, 64); text-transform: none; text-indent: 0px; letter-spacing: normal; word-spacing: 0px; white-space: normal; orphans: 2; widows: 2; font-size-adjust: none; font-stretch: normal; background-color: rgb(255, 255, 255); -webkit-text-stroke-width: 0px; text-decoration-style: initial; text-decoration-color: initial;\"><img style=\"border: 0px currentColor; border-image: none; vertical-align: top;\" alt=\"60㎡老房仅花27天变高科技住宅，6人生活毫不拥挤\" src=\"http://cms-bucket.nosdn.127.net/2018/07/31/071d42dc3ae640cbaa3c59125ee316c8.jpeg?imageView&thumbnail=550x0\"/><br/></p><p style=\"font: 400 18px/32px &quot;Microsoft Yahei&quot;; margin: 32px 0px 0px; padding: 0px; text-align: justify; color: rgb(64, 64, 64); text-transform: none; text-indent: 2em; letter-spacing: normal; word-spacing: 0px; white-space: normal; orphans: 2; widows: 2; font-size-adjust: none; font-stretch: normal; background-color: rgb(255, 255, 255); -webkit-text-stroke-width: 0px; text-decoration-style: initial; text-decoration-color: initial;\">改造后的房子用了很多高科技的家具，例如电动床，只需要用遥控器就可以把床从收纳柜里变出来。</p><p class=\"f_center\" style=\"font: 400 18px/32px &quot;Microsoft Yahei&quot;; margin: 32px 0px 0px; padding: 0px; text-align: center; color: rgb(64, 64, 64); text-transform: none; text-indent: 0px; letter-spacing: normal; word-spacing: 0px; white-space: normal; orphans: 2; widows: 2; font-size-adjust: none; font-stretch: normal; background-color: rgb(255, 255, 255); -webkit-text-stroke-width: 0px; text-decoration-style: initial; text-decoration-color: initial;\"><img style=\"border: 0px currentColor; border-image: none; vertical-align: top;\" alt=\"60㎡老房仅花27天变高科技住宅，6人生活毫不拥挤\" src=\"http://cms-bucket.nosdn.127.net/2018/07/31/276f23f546234e1584d4458895b8f800.jpeg?imageView&thumbnail=550x0\"/><br/></p><p style=\"font: 400 18px/32px &quot;Microsoft Yahei&quot;; margin: 32px 0px 0px; padding: 0px; text-align: justify; color: rgb(64, 64, 64); text-transform: none; text-indent: 2em; letter-spacing: normal; word-spacing: 0px; white-space: normal; orphans: 2; widows: 2; font-size-adjust: none; font-stretch: normal; background-color: rgb(255, 255, 255); -webkit-text-stroke-width: 0px; text-decoration-style: initial; text-decoration-color: initial;\">家居妹这就带大家看看这间60平方米的老房子，看看这一家六口是怎么住在这间房子里的呢？</p><p>&nbsp;</p>', '0', '2', '1', '7a0586b8753540e6b686e31142f571ee', '1', '1', 'app', null);
