INSERT INTO `web_news` VALUES ('4054bd29834e4a63aecac031e371747e', '50b79e1fc9654c0282792e8fa9f78ed0', '重庆一镇政府公款吃喝欠2斤白条：镇党委书记被查', '2018-08-01 14:28:51', '重庆一镇政府公款吃喝欠2斤白条：镇党委书记被查', 'http://222.137.19.253:8086/dashop/uploadFiles/uploadImgs/20180801/ba4562150d74412bb3c16bb826bd702b.jpg', '彭水苗族土家族自治县大同镇党委书记冉宇航涉嫌严重违纪违法接受重庆市纪委监委纪律审查和监察调查', '<p style=\"font: 400 18px/32px &quot;Microsoft Yahei&quot;; margin: 32px 0px 0px; padding: 0px; text-align: justify; color: rgb(64, 64, 64); text-transform: none; text-indent: 2em; letter-spacing: normal; word-spacing: 0px; white-space: normal; orphans: 2; widows: 2; font-size-adjust: none; font-stretch: normal; background-color: rgb(255, 255, 255); -webkit-text-stroke-width: 0px; text-decoration-style: initial; text-decoration-color: initial;\">彭水苗族土家族自治县大同镇党委书记冉宇航涉嫌严重违纪违法，7月29日接受重庆市纪委监委纪律审查和监察调查。</p><p style=\"font: 400 18px/32px &quot;Microsoft Yahei&quot;; margin: 32px 0px 0px; padding: 0px; text-align: justify; color: rgb(64, 64, 64); text-transform: none; text-indent: 2em; letter-spacing: normal; word-spacing: 0px; white-space: normal; orphans: 2; widows: 2; font-size-adjust: none; font-stretch: normal; background-color: rgb(255, 255, 255); -webkit-text-stroke-width: 0px; text-decoration-style: initial; text-decoration-color: initial;\"><strong style=\"font-style: normal; font-weight: bold;\">冉宇航简历</strong></p><p style=\"font: 400 18px/32px &quot;Microsoft Yahei&quot;; margin: 32px 0px 0px; padding: 0px; text-align: justify; color: rgb(64, 64, 64); text-transform: none; text-indent: 2em; letter-spacing: normal; word-spacing: 0px; white-space: normal; orphans: 2; widows: 2; font-size-adjust: none; font-stretch: normal; background-color: rgb(255, 255, 255); -webkit-text-stroke-width: 0px; text-decoration-style: initial; text-decoration-color: initial;\">冉宇航，男，土家族，1978年4月出生，重庆彭水人，在职研究生，1997年11月参加工作，2004年6月加入中国共产党。</p><p style=\"font: 400 18px/32px &quot;Microsoft Yahei&quot;; margin: 32px 0px 0px; padding: 0px; text-align: justify; color: rgb(64, 64, 64); text-transform: none; text-indent: 2em; letter-spacing: normal; word-spacing: 0px; white-space: normal; orphans: 2; widows: 2; font-size-adjust: none; font-stretch: normal; background-color: rgb(255, 255, 255); -webkit-text-stroke-width: 0px; text-decoration-style: initial; text-decoration-color: initial;\">1994.09—1997.07涪陵水利电力学校工业与民用建筑专业中专学习</p><p style=\"font: 400 18px/32px &quot;Microsoft Yahei&quot;; margin: 32px 0px 0px; padding: 0px; text-align: justify; color: rgb(64, 64, 64); text-transform: none; text-indent: 2em; letter-spacing: normal; word-spacing: 0px; white-space: normal; orphans: 2; widows: 2; font-size-adjust: none; font-stretch: normal; background-color: rgb(255, 255, 255); -webkit-text-stroke-width: 0px; text-decoration-style: initial; text-decoration-color: initial;\">1997.07—1997.11待分配</p><p style=\"font: 400 18px/32px &quot;Microsoft Yahei&quot;; margin: 32px 0px 0px; padding: 0px; text-align: justify; color: rgb(64, 64, 64); text-transform: none; text-indent: 2em; letter-spacing: normal; word-spacing: 0px; white-space: normal; orphans: 2; widows: 2; font-size-adjust: none; font-stretch: normal; background-color: rgb(255, 255, 255); -webkit-text-stroke-width: 0px; text-decoration-style: initial; text-decoration-color: initial;\">1997.11—2000.06 重庆市黔江开发区彭水自治县汉葭区文武乡政府工作</p><p style=\"font: 400 18px/32px &quot;Microsoft Yahei&quot;; margin: 32px 0px 0px; padding: 0px; text-align: justify; color: rgb(64, 64, 64); text-transform: none; text-indent: 2em; letter-spacing: normal; word-spacing: 0px; white-space: normal; orphans: 2; widows: 2; font-size-adjust: none; font-stretch: normal; background-color: rgb(255, 255, 255); -webkit-text-stroke-width: 0px; text-decoration-style: initial; text-decoration-color: initial;\">2000.06—2001.08 重庆市彭水自治县汉葭区文武乡政府工作</p><p style=\"font: 400 18px/32px &quot;Microsoft Yahei&quot;; margin: 32px 0px 0px; padding: 0px; text-align: justify; color: rgb(64, 64, 64); text-transform: none; text-indent: 2em; letter-spacing: normal; word-spacing: 0px; white-space: normal; orphans: 2; widows: 2; font-size-adjust: none; font-stretch: normal; background-color: rgb(255, 255, 255); -webkit-text-stroke-width: 0px; text-decoration-style: initial; text-decoration-color: initial;\">2001.08—2003.04 重庆市彭水自治县汉葭区靛水乡政府工作</p><p style=\"font: 400 18px/32px &quot;Microsoft Yahei&quot;; margin: 32px 0px 0px; padding: 0px; text-align: justify; color: rgb(64, 64, 64); text-transform: none; text-indent: 2em; letter-spacing: normal; word-spacing: 0px; white-space: normal; orphans: 2; widows: 2; font-size-adjust: none; font-stretch: normal; background-color: rgb(255, 255, 255); -webkit-text-stroke-width: 0px; text-decoration-style: initial; text-decoration-color: initial;\">2003.04—2007.10 重庆市彭水自治县靛水乡团委书记（2002.09—2004.10重庆广播电视大学专科行政管理专业学习，2005.08—2007.10抽调到百万吨水泥厂指挥部办公室工作）</p><p style=\"font: 400 18px/32px &quot;Microsoft Yahei&quot;; margin: 32px 0px 0px; padding: 0px; text-align: justify; color: rgb(64, 64, 64); text-transform: none; text-indent: 2em; letter-spacing: normal; word-spacing: 0px; white-space: normal; orphans: 2; widows: 2; font-size-adjust: none; font-stretch: normal; background-color: rgb(255, 255, 255); -webkit-text-stroke-width: 0px; text-decoration-style: initial; text-decoration-color: initial;\">2007.10—2009.02 重庆市彭水自治县经贸委工作</p><p style=\"font: 400 18px/32px &quot;Microsoft Yahei&quot;; margin: 32px 0px 0px; padding: 0px; text-align: justify; color: rgb(64, 64, 64); text-transform: none; text-indent: 2em; letter-spacing: normal; word-spacing: 0px; white-space: normal; orphans: 2; widows: 2; font-size-adjust: none; font-stretch: normal; background-color: rgb(255, 255, 255); -webkit-text-stroke-width: 0px; text-decoration-style: initial; text-decoration-color: initial;\">2009.02—2010.03 重庆市彭水自治县县委办副主任科员（2007.09—2009.12中共重庆市委党校本科班公管专业学习）</p><p style=\"font: 400 18px/32px &quot;Microsoft Yahei&quot;; margin: 32px 0px 0px; padding: 0px; text-align: justify; color: rgb(64, 64, 64); text-transform: none; text-indent: 2em; letter-spacing: normal; word-spacing: 0px; white-space: normal; orphans: 2; widows: 2; font-size-adjust: none; font-stretch: normal; background-color: rgb(255, 255, 255); -webkit-text-stroke-width: 0px; text-decoration-style: initial; text-decoration-color: initial;\">2010.03—2010.10 重庆市彭水自治县县委办秘书二科科长</p><p style=\"font: 400 18px/32px &quot;Microsoft Yahei&quot;; margin: 32px 0px 0px; padding: 0px; text-align: justify; color: rgb(64, 64, 64); text-transform: none; text-indent: 2em; letter-spacing: normal; word-spacing: 0px; white-space: normal; orphans: 2; widows: 2; font-size-adjust: none; font-stretch: normal; background-color: rgb(255, 255, 255); -webkit-text-stroke-width: 0px; text-decoration-style: initial; text-decoration-color: initial;\">2010.10—2012.02 重庆市彭水自治县县委办综合科长</p><p style=\"font: 400 18px/32px &quot;Microsoft Yahei&quot;; margin: 32px 0px 0px; padding: 0px; text-align: justify; color: rgb(64, 64, 64); text-transform: none; text-indent: 2em; letter-spacing: normal; word-spacing: 0px; white-space: normal; orphans: 2; widows: 2; font-size-adjust: none; font-stretch: normal; background-color: rgb(255, 255, 255); -webkit-text-stroke-width: 0px; text-decoration-style: initial; text-decoration-color: initial;\">2012.02—2016.02 重庆市彭水自治县县委办副主任</p><p style=\"font: 400 18px/32px &quot;Microsoft Yahei&quot;; margin: 32px 0px 0px; padding: 0px; text-align: justify; color: rgb(64, 64, 64); text-transform: none; text-indent: 2em; letter-spacing: normal; word-spacing: 0px; white-space: normal; orphans: 2; widows: 2; font-size-adjust: none; font-stretch: normal; background-color: rgb(255, 255, 255); -webkit-text-stroke-width: 0px; text-decoration-style: initial; text-decoration-color: initial;\">2016.02—2016.11 重庆市彭水自治县大同镇党委副书记、镇长</p><p></p>', '0', '1', '3', '7a0586b8753540e6b686e31142f571ee,4aa1eecf0322489da0036998856266b7,dcd244ce18674c3f8c258411631a1baf', '1', '1', 'app', null);
