INSERT INTO `weixin_textmsg` VALUES ('695cd74779734231928a253107ab0eeb', '公司简介', '河南大岸信息技术有限公司创建于2012年，专注于企事业单位设备资产管理问题，提供企业设备资产全生命周期管理解决方案和设备维护管理系统实施服务。我们的自由产品DA-EAM系统，是专门由资深行业专家设计和开发的设备资产全生命周期管理系统，拥有多项著作权证书，完全自主产权。适合企事业单位和工厂使用并可以获得量化的收益，云端部署和本地部署皆可。', '2015-05-10 22:52:27', '1', '文本回复');
INSERT INTO `weixin_textmsg` VALUES ('d4738af7aea74a6ca1a5fb25a98f9acb', '关注', '河南大岸信息技术有限公司创建于2012年，专注于企事业单位设备资产管理问题，提供企业设备资产全生命周期管理解决方案和设备维护管理系统实施服务。我们的自由产品DA-EAM系统，是专门由资深行业专家设计和开发的设备资产全生命周期管理系统，拥有多项著作权证书，完全自主产权。适合企事业单位和工厂使用并可以获得量化的收益，云端部署和本地部署皆可。', '2015-05-11 02:12:36', '1', '关注回复');
