DROP TABLE IF EXISTS `shop_goods`;
CREATE TABLE `shop_goods` (
  `GOODS_ID` varchar(100) NOT NULL,
  `GOODS_PIC` varchar(255) DEFAULT NULL COMMENT '图片',
  `GOODS_NAME` varchar(255) DEFAULT NULL COMMENT '名称',
  `GOODS_TITLE` varchar(255) DEFAULT NULL COMMENT '标题',
  `GOODS_PRICE` double(10,2) DEFAULT NULL COMMENT '本店售格',
  `GOODS_NUM` int(11) DEFAULT NULL COMMENT '数量',
  `GOODS_CODE` varchar(255) DEFAULT NULL COMMENT '编号',
  `GOODS_NUMBER` varchar(255) DEFAULT NULL COMMENT '货号',
  `GOODS_FORSALE` int(11) DEFAULT NULL COMMENT '上架',
  `GOODS_BEST` int(11) DEFAULT NULL COMMENT '精品',
  `GOODS_NEW` int(11) DEFAULT NULL COMMENT '新品',
  `GOODS_HOT` int(11) DEFAULT NULL COMMENT '热销',
  `GOODS_BRAND` varchar(255) DEFAULT NULL COMMENT '品牌',
  `MEMBER_PRICE` double(11,2) DEFAULT NULL COMMENT '会员价格',
  `GOODS_DISCOUNT1` int(11) DEFAULT NULL COMMENT '商品优惠数量',
  `GOODS_DISCOUNT2` double(11,2) DEFAULT NULL COMMENT '商品优惠价格',
  `MARKET_PRICE` varchar(255) DEFAULT NULL COMMENT '市场售价',
  `MEMBER_GIFTPOINTS` int(11) DEFAULT NULL COMMENT '赠送消费积分数',
  `MEMBER_LEVGIFTPOINTS` int(11) DEFAULT NULL COMMENT '赠送等级积分数',
  `MEMBER_POINTTOPRICE` double(11,2) DEFAULT NULL COMMENT '积分购买金额',
  `ACTIVITY_PRICE` double(11,2) DEFAULT NULL COMMENT '促销价',
  `ACTIVITY_DATE1` varchar(32) DEFAULT NULL COMMENT '促销开始日期',
  `GOODS_THUMBNAIL` varchar(255) DEFAULT NULL COMMENT '缩略图',
  `GOODS_DETAILS` varchar(255) DEFAULT NULL COMMENT '详细描述',
  `GOODS_WEIGHT` double(11,2) DEFAULT NULL COMMENT '重量',
  `GOODS_LOW` double(11,2) DEFAULT NULL COMMENT '库存警告数量',
  `GOODS_CUSTOM` int(11) DEFAULT NULL COMMENT '能作为普通商品销售',
  `GOODS_FREETRAFFIC` int(11) DEFAULT NULL COMMENT '是否为免运费商品',
  `GOODS_KEYWORDS` varchar(255) DEFAULT NULL COMMENT '商品关键词',
  `GOODS_INTRODUCTION` varchar(255) DEFAULT NULL COMMENT '商品简介',
  `GOODS_ORDER` int(11) DEFAULT NULL COMMENT '排序',
  `ACTIVITY_DATE2` varchar(32) DEFAULT NULL COMMENT '促销结束日期',
  `GOODS_DELFLAG` int(11) DEFAULT NULL COMMENT '删除标记',
  `GOODS_MODEL` varchar(255) DEFAULT NULL COMMENT '规格型号',
  `GOODS_CATEGORY` varchar(255) DEFAULT NULL,
  `GOODS_CATEGORY1` varchar(2550) DEFAULT NULL,
  `GOODS_CATEGORY2` varchar(255) DEFAULT NULL,
  `GOODS_CATEGORY3` varchar(255) DEFAULT NULL,
  `GOODS_CATEGORY4` varchar(255) DEFAULT NULL,
  `GOODS_DETAILSPIC` varchar(1000) DEFAULT NULL,
